import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { Song, UserPlaylist, User, Friend, ChatMessage, PartySession, Artist } from '../types';
import { authService } from '../services/auth';
import { downloadSongWithProgress, OfflineStorage } from '../services/api';

interface PlayerState {
  isPlaying: boolean;
  isBuffering: boolean;
  isFullScreen: boolean;
  currentSong: Song | null;
  queue: Song[];
  history: Song[];
  likedSongs: Song[];
  favoriteArtists: Artist[];
  userPlaylists: UserPlaylist[];
  volume: number;
  isShuffling: boolean;
  streamingQuality: 'low' | 'normal' | 'high';

  // Offline & Downloads
  isOfflineMode: boolean;
  downloadedSongIds: string[];
  activeDownload: Song | null;
  downloadProgress: number;

  // Auth
  currentUser: User | null;

  // Social
  friends: Friend[]; // Unified list
  searchResults: { name: string, email: string, image?: string }[];
  activeChatFriendId: string | null;
  partySession: PartySession | null;

  // Realtime Cleanup
  unsubscribers: Function[];

  // Actions
  playSong: (song: Song, newQueue?: Song[]) => void;
  togglePlay: () => void;
  setIsPlaying: (isPlaying: boolean) => void;
  setIsBuffering: (isBuffering: boolean) => void;
  setFullScreen: (isFull: boolean) => void;
  nextSong: () => void;
  prevSong: () => void;
  addToQueue: (song: Song) => void;
  setQueue: (songs: Song[]) => void;
  setVolume: (val: number) => void;
  addToHistory: (song: Song) => void;
  toggleLike: (song: Song) => void;
  toggleArtistLike: (artist: Artist) => void;
  createPlaylist: (playlist: UserPlaylist) => void;
  importPlaylist: (playlist: UserPlaylist) => void;
  addSongToPlaylist: (playlistId: string, song: Song) => void;
  removePlaylist: (id: string) => void;
  setStreamingQuality: (quality: 'low' | 'normal' | 'high') => void;
  startDownload: (song: Song, url: string, filename: string) => Promise<void>;

  // Network Actions
  setOfflineMode: (isOffline: boolean) => void;

  // Auth Actions
  loginUser: (user: User & { likedSongs?: Song[], history?: Song[], favoriteArtists?: Artist[], chats?: any }) => void;
  logoutUser: () => void;
  syncUserToCloud: (type?: 'public' | 'private' | 'both') => void;
  updateUserProfile: (name: string, image?: string) => void;
  initRealtimeListeners: () => void;

  // Social Actions
  searchUsers: (query: string) => Promise<void>;
  addContact: (email: string) => Promise<void>;
  refreshFriendsActivity: () => Promise<void>;
  openChat: (friendId: string | null) => void;
  sendMessage: (friendId: string, text: string) => void;
  startParty: () => void;
  stopParty: () => void;
}

export const usePlayerStore = create<PlayerState>()(
  persist(
    (set, get) => ({
      isPlaying: false,
      isBuffering: false,
      isFullScreen: false,
      currentSong: null,
      queue: [],
      history: [],
      likedSongs: [],
      favoriteArtists: [],
      userPlaylists: [],
      volume: 1,
      isShuffling: false,
      currentUser: null,
      streamingQuality: 'high',

      // Offline State
      isOfflineMode: !navigator.onLine,
      downloadedSongIds: [],
      activeDownload: null,
      downloadProgress: 0,

      // Social Initial State
      friends: [],
      searchResults: [],
      activeChatFriendId: null,
      partySession: null,
      unsubscribers: [],

      setOfflineMode: (isOffline) => set({ isOfflineMode: isOffline }),

      playSong: (song, newQueue) => {
        const { addToHistory, currentUser } = get();
        addToHistory(song);

        if (currentUser && navigator.onLine) {
            authService.updateUserStatus('listening', song);
        }

        set((state) => ({
          currentSong: song,
          isPlaying: true,
          isBuffering: true, 
          queue: newQueue ? newQueue : state.queue,
          isFullScreen: false, 
        }));
      },

      togglePlay: () => set((state) => ({ isPlaying: !state.isPlaying })),

      setIsPlaying: (isPlaying) => {
          set({ isPlaying });
          const { currentUser, currentSong, isOfflineMode } = get();
          if (currentUser && !isPlaying && !isOfflineMode) {
             authService.updateUserStatus('online', currentSong);
          }
      },

      setIsBuffering: (isBuffering) => set({ isBuffering }),
      setFullScreen: (isFullScreen) => set({ isFullScreen }),

      nextSong: () => {
        const { queue, currentSong, isShuffling } = get();
        if (!currentSong) return;
        const currentIndex = queue.findIndex(s => s.id === currentSong.id);
        let nextIndex = isShuffling ? Math.floor(Math.random() * queue.length) : currentIndex + 1;
        if (nextIndex < queue.length) get().playSong(queue[nextIndex]);
        else set({ isPlaying: false });
      },

      prevSong: () => {
        const { queue, currentSong } = get();
        if (!currentSong) return;
        const currentIndex = queue.findIndex(s => s.id === currentSong.id);
        if (currentIndex - 1 >= 0) get().playSong(queue[currentIndex - 1]);
      },

      addToQueue: (song) => set((state) => ({ queue: [...state.queue, song] })),
      setQueue: (songs) => set({ queue: songs }),
      setVolume: (volume) => set({ volume }),
      setStreamingQuality: (quality) => set({ streamingQuality: quality }),

      addToHistory: (song) => {
          set((state) => {
            const newHistory = [song, ...state.history.filter(s => s.id !== song.id)].slice(0, 20);
            if(navigator.onLine) setTimeout(() => get().syncUserToCloud('private'), 1000);
            return { history: newHistory };
          });
      },

      toggleLike: (song) => {
          set((state) => {
            const isLiked = state.likedSongs.some(s => s.id === song.id);
            const newLiked = isLiked ? state.likedSongs.filter(s => s.id !== song.id) : [song, ...state.likedSongs];
            if(navigator.onLine) setTimeout(() => get().syncUserToCloud('private'), 1000);
            return { likedSongs: newLiked };
          });
      },

      toggleArtistLike: (artist) => {
          set((state) => {
              const isLiked = state.favoriteArtists.some(a => a.id === artist.id);
              const newLiked = isLiked 
                  ? state.favoriteArtists.filter(a => a.id !== artist.id) 
                  : [...state.favoriteArtists, artist];
              return { favoriteArtists: newLiked };
          });
      },

      createPlaylist: (playlist) => {
        set((state) => {
           const newPlaylists = [playlist, ...state.userPlaylists];
           if(navigator.onLine) authService.savePublicPlaylist(playlist);
           if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             if(navigator.onLine) setTimeout(() => get().syncUserToCloud('private'), 1000);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      importPlaylist: (playlist) => {
        set((state) => {
           if (state.userPlaylists.some(p => p.id === playlist.id)) return {};
           const newPlaylists = [playlist, ...state.userPlaylists];
           if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             if(navigator.onLine) setTimeout(() => get().syncUserToCloud('private'), 1000);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      addSongToPlaylist: (playlistId, song) => {
        set((state) => {
          const newPlaylists = state.userPlaylists.map(p => {
            if (p.id === playlistId) {
               const updated = { ...p, songs: [...p.songs, song] };
               if (p.songs.some(s => s.id === song.id)) return p;
               if(navigator.onLine) authService.savePublicPlaylist(updated);
               return updated;
            }
            return p;
          });
          if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             if(navigator.onLine) setTimeout(() => get().syncUserToCloud('private'), 1000);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      removePlaylist: (id) => {
        set((state) => {
           const newPlaylists = state.userPlaylists.filter(p => p.id !== id);
           if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             if(navigator.onLine) setTimeout(() => get().syncUserToCloud('private'), 1000);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      startDownload: async (song, url, filename) => {
         set({ activeDownload: song, downloadProgress: 0 });
         try {
             await downloadSongWithProgress(song.id, url, filename, (progress) => {
                 set({ downloadProgress: progress });
             });

             // Mark as downloaded in state
             set(state => {
                 const newDownloads = state.downloadedSongIds.includes(song.id) 
                    ? state.downloadedSongIds 
                    : [...state.downloadedSongIds, song.id];
                 return { downloadProgress: 100, downloadedSongIds: newDownloads };
             });

             // Wait a bit before closing progress
             setTimeout(() => {
                 set({ activeDownload: null, downloadProgress: 0 });
             }, 2000);
         } catch (e) {
             console.error("Download Error", e);
             set({ activeDownload: null, downloadProgress: 0 });
         }
      },

      loginUser: (user) => {
          set({ 
            currentUser: user, 
            userPlaylists: user.playlists || [],
            likedSongs: user.likedSongs || [],
            history: user.history || [],
            favoriteArtists: user.favoriteArtists || []
          });
          get().initRealtimeListeners();
      },

      initRealtimeListeners: () => {
         const { unsubscribers, currentUser } = get();
         unsubscribers.forEach(unsub => unsub());

         if (!currentUser || !navigator.onLine) {
             set({ unsubscribers: [] });
             return;
         }

         const newUnsubscribers: Function[] = [];

         const unsubUser = authService.subscribeToUserData((data) => {
             set((state) => {
                 const updatedUser = { ...state.currentUser, ...data } as User;
                 const existingFriends = state.friends;
                 const serverContactEmails = data.friends || [];
                 const serverChats = data.chats || {};

                 const mergedFriends: Friend[] = serverContactEmails.map((email: string) => {
                     const existing = existingFriends.find(f => f.id === email);
                     const chatHistory = serverChats[email] || serverChats[email.replace(/\./g, '_dot_')] || [];
                     return {
                         id: email,
                         name: existing?.name || email.split('@')[0], 
                         image: existing?.image || '',
                         status: existing?.status || 'offline', 
                         currentSong: existing?.currentSong || null, 
                         lastActive: existing?.lastActive || 0,
                         chatHistory: chatHistory
                     };
                 });

                 return {
                     currentUser: updatedUser,
                     friends: mergedFriends,
                     userPlaylists: data.playlists || state.userPlaylists
                 };
             });
         });
         newUnsubscribers.push(unsubUser);

         if (currentUser.friends && currentUser.friends.length > 0) {
             const unsubFriends = authService.subscribeToFriendsActivity(currentUser.friends, (friendsData) => {
                 set((state) => {
                     const updatedFriends = state.friends.map(f => {
                         const liveData = friendsData.find((d: any) => d.email === f.id);
                         if (liveData) {
                             return {
                                 ...f,
                                 name: liveData.name || f.name,
                                 image: liveData.image || f.image,
                                 status: liveData.currentActivity?.status || 'offline',
                                 currentSong: liveData.currentActivity?.song || null,
                                 lastActive: liveData.currentActivity?.timestamp || 0
                             };
                         }
                         return f;
                     });
                     return { friends: updatedFriends };
                 });
             });
             newUnsubscribers.push(unsubFriends);
         }

         set({ unsubscribers: newUnsubscribers });
      },

      logoutUser: async () => {
        get().unsubscribers.forEach(unsub => unsub());
        if(navigator.onLine) await authService.logout();
        set({ 
            currentUser: null, 
            userPlaylists: [],
            friends: [],
            partySession: null,
            likedSongs: [],
            history: [],
            favoriteArtists: [],
            unsubscribers: []
        });
      },

      syncUserToCloud: async (type = 'both') => {
         const { currentUser, userPlaylists, likedSongs, history, favoriteArtists, isOfflineMode } = get();
         if (!currentUser || isOfflineMode) return;
         const updatedUser = { ...currentUser, playlists: userPlaylists };
         try {
             if (type === 'public' || type === 'both') await authService.syncPublicProfile(updatedUser);
             if (type === 'private' || type === 'both') await authService.syncPrivateData(updatedUser, { likedSongs, history, favoriteArtists });
         } catch (e) {
             console.error("Sync failed", e);
         }
      },

      updateUserProfile: (name, image) => {
        set((state) => {
          if (!state.currentUser) return {};
          const updatedUser = { 
              ...state.currentUser, 
              name: name,
              image: image !== undefined ? image : state.currentUser.image 
          };
          setTimeout(() => get().syncUserToCloud('public'), 100);
          return { currentUser: updatedUser };
        });
      },

      searchUsers: async (query) => {
          try {
              if (!navigator.onLine) return;
              const results = await authService.searchUsers(query);
              const { currentUser } = get();
              const filtered = results.filter(u => u.email !== currentUser?.email);
              set({ searchResults: filtered });
          } catch (e) { console.error(e); }
      },

      addContact: async (email) => {
          const { currentUser } = get();
          if (!currentUser || !navigator.onLine) return;
          await authService.addContact(email);
          set((state) => {
              if (state.friends.some(f => f.id === email)) return {};
              const newFriend: Friend = {
                  id: email,
                  name: email.split('@')[0],
                  image: '',
                  status: 'offline',
                  lastActive: 0,
                  chatHistory: []
              };
              return { 
                  friends: [...state.friends, newFriend],
                  activeChatFriendId: email 
              };
          });
          setTimeout(() => {
              get().initRealtimeListeners();
          }, 500);
      },

      refreshFriendsActivity: async () => {
          get().initRealtimeListeners();
      },

      openChat: (friendId) => set({ activeChatFriendId: friendId }),

      sendMessage: async (friendId, text) => {
          const { currentUser } = get();
          if (!currentUser) return;

          const newMessage: ChatMessage = {
              id: `msg-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
              senderId: currentUser.email,
              text,
              timestamp: Date.now()
          };

          set((state) => {
              const updatedFriends = state.friends.map(f => {
                  if (f.id === friendId) {
                      return { ...f, chatHistory: [...f.chatHistory, newMessage] };
                  }
                  return f;
              });
              return { friends: updatedFriends };
          });

          if(navigator.onLine) {
             await authService.sendChatMessage(currentUser.email, friendId, newMessage);
          }
      },

      startParty: () => set((state) => {
         if (!state.currentUser) return {};
         return {
             partySession: {
                 isActive: true,
                 hostId: 'me',
                 hostName: state.currentUser.name,
                 listeners: state.activeChatFriendId ? [state.activeChatFriendId] : []
             }
         }
      }),

      stopParty: () => set({ partySession: null })
    }),
    {
      name: 'vibestream-storage',
      partialize: (state) => ({ 
        history: state.history, 
        volume: state.volume,
        likedSongs: state.likedSongs,
        favoriteArtists: state.favoriteArtists,
        userPlaylists: state.userPlaylists,
        currentUser: state.currentUser,
        streamingQuality: state.streamingQuality,
        downloadedSongIds: state.downloadedSongIds, // Persist download list
      }), 
    }
  )
);

import React, { useRef, useEffect, useState } from 'react';
import { Play, Pause, SkipBack, SkipForward, ChevronDown, MoreHorizontal, Download, ListMusic, Heart, Loader2, Shuffle, Repeat, Mic2, PlusCircle, CheckCircle2 } from 'lucide-react';
import { usePlayerStore } from '../store/playerStore';
import { getImageUrl, getAudioUrl, getOfflineAudioUrl } from '../services/api';
import { AnimatePresence, motion } from 'framer-motion';
import { DownloadQualityModal } from './DownloadQualityModal';
import { Song } from '../types';

export const Player: React.FC = () => {
  const { 
    currentSong, 
    isPlaying, 
    isBuffering,
    isFullScreen,
    setFullScreen,
    togglePlay, 
    setIsPlaying, 
    setIsBuffering,
    nextSong, 
    prevSong,
    likedSongs,
    toggleLike,
    isShuffling,
    streamingQuality,
    isOfflineMode,
    downloadedSongIds
  } = usePlayerStore();

  const audioRef = useRef<HTMLAudioElement>(null);
  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);
  const [dominantColor, setDominantColor] = useState<string>('#121212');
  const [isDragging, setIsDragging] = useState(false);
  const [downloadSong, setDownloadSong] = useState<Song | null>(null);
  const [touchStart, setTouchStart] = useState<{x: number, y: number} | null>(null);

  const isLiked = currentSong ? likedSongs.some(s => s.id === currentSong.id) : false;
  const isDownloaded = currentSong ? downloadedSongIds.includes(currentSong.id) : false;

  useEffect(() => {
    if (!currentSong) return;

    const imgUrl = getImageUrl(currentSong.image);
    const img = new Image();
    img.crossOrigin = "Anonymous";
    img.src = imgUrl;

    img.onload = () => {
      try {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) return;
        canvas.width = 1;
        canvas.height = 1;
        ctx.drawImage(img, 0, 0, 1, 1);
        const [r, g, b] = ctx.getImageData(0, 0, 1, 1).data;
        setDominantColor(`rgb(${r},${g},${b})`);
      } catch (e) {
        setDominantColor('#2a2a2a'); 
      }
    };
    img.onerror = () => setDominantColor('#2a2a2a');
  }, [currentSong?.id]);

  useEffect(() => {
    if (!currentSong || !audioRef.current) return;

    const setAudioSource = async () => {
        let url = '';

        // OFFLINE LOGIC: If offline mode OR song is known to be downloaded, try IDB first
        if (isOfflineMode || downloadedSongIds.includes(currentSong.id)) {
            const blobUrl = await getOfflineAudioUrl(currentSong.id);
            if (blobUrl) {
                url = blobUrl;
                console.log("Playing from Offline Storage");
            } else if (isOfflineMode) {
                // Song marked as downloaded but missing blob, or offline with no download
                console.warn("Song not available offline");
                // Stop trying to play
                setIsPlaying(false);
                return;
            }
        }

        // Fallback to Network if no offline blob found and we are Online
        if (!url && !isOfflineMode) {
             url = getAudioUrl(currentSong.downloadUrl, streamingQuality);
        }

        if (url && audioRef.current && audioRef.current.src !== url) {
            const wasPlaying = isPlaying;
            audioRef.current.src = url;
            audioRef.current.load();
            if (wasPlaying) {
                 const playPromise = audioRef.current.play();
                 if (playPromise !== undefined) {
                     playPromise.catch(error => {
                         console.warn("Autoplay prevented:", error);
                         setIsPlaying(false);
                     });
                 }
            }
        }
    };

    setAudioSource();

    // Cleanup blob URLs if we switch
    return () => {
        if (audioRef.current?.src.startsWith('blob:')) {
            URL.revokeObjectURL(audioRef.current.src);
        }
    };
  }, [currentSong?.id, streamingQuality, isOfflineMode, downloadedSongIds]);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;
    if (isPlaying && audio.paused) audio.play().catch(e => console.warn("Play interrupted", e));
    else if (!isPlaying && !audio.paused) audio.pause();
  }, [isPlaying]);

  const handleTimeUpdate = () => {
    if (audioRef.current && !isDragging) {
      setProgress(audioRef.current.currentTime);
      setDuration(audioRef.current.duration || 0);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);
    setProgress(time);
    if (audioRef.current) audioRef.current.currentTime = time;
  };

  const handleSeekStart = () => setIsDragging(true);
  const handleSeekEnd = () => {
      setIsDragging(false);
       if (audioRef.current) audioRef.current.currentTime = progress;
  };

  const formatTime = (seconds: number) => {
    if (!seconds || isNaN(seconds)) return "-:--";
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    setTouchStart({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY });
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (!touchStart) return;
    const touchEndX = e.changedTouches[0].clientX;
    const touchEndY = e.changedTouches[0].clientY;
    const diffX = touchStart.x - touchEndX;
    const diffY = touchStart.y - touchEndY;

    if (Math.abs(diffX) > 50 && Math.abs(diffX) > Math.abs(diffY)) {
      if (diffX > 0) nextSong();
      else prevSong();
    }

    // Swipe Down to close
    if (diffY < -80 && Math.abs(diffY) > Math.abs(diffX)) {
        setFullScreen(false);
    }
    setTouchStart(null);
  };

  if (!currentSong) return null;

  const imageUrl = getImageUrl(currentSong.image);
  const primaryArtistName = currentSong.artists?.primary?.[0]?.name || currentSong.artists?.all?.[0]?.name || "Unknown Artist";

  // High-performance spring physics
  const transitionConfig = {
    type: "spring",
    stiffness: 280,
    damping: 28,
    mass: 0.8
  };

  return (
    <>
        <audio 
            ref={audioRef}
            preload="auto"
            onTimeUpdate={handleTimeUpdate}
            onEnded={nextSong}
            onWaiting={() => setIsBuffering(true)}
            onPlaying={() => setIsBuffering(false)}
            onCanPlay={() => setIsBuffering(false)}
            onPause={() => {
                if (isPlaying && !isBuffering && audioRef.current?.paused && audioRef.current?.readyState > 2) setIsPlaying(false);
            }}
            onPlay={() => !isPlaying && setIsPlaying(true)}
            onError={() => { setIsBuffering(false); setIsPlaying(false); }}
        />

        {/* 
            OPTIMIZATION: 
            Removed layoutId="player-container" to prevent heavy layout thrashing.
            The Full Player now slides up (y-axis) while the image morphs (layoutId="player-image").
            This combination provides the native feel without the lag.
        */}

        <AnimatePresence mode="wait"> 
        {isFullScreen ? (
            /* --- FULL PLAYER --- */
            <motion.div 
                key="full-player"
                initial={{ y: "100%" }}
                animate={{ y: 0 }}
                exit={{ y: "100%" }}
                transition={{ 
                   type: "spring", 
                   stiffness: 250, 
                   damping: 25,
                   mass: 0.8
                }}
                className="fixed inset-0 z-[200] flex flex-col bg-[#121212] overflow-hidden font-sans touch-none"
                onClick={(e) => e.stopPropagation()}
                onTouchStart={handleTouchStart}
                onTouchEnd={handleTouchEnd}
            >
                {/* Dynamic Background */}
                <div 
                    className="absolute inset-0 z-0 pointer-events-none transition-colors duration-700 ease-in-out"
                    style={{ background: `linear-gradient(to bottom, ${dominantColor}, #121212)` }}
                />

                <div className="relative z-10 flex flex-col h-full text-white px-6 pb-8 pt-safe-top md:px-12 md:pb-12">

                    {/* Header */}
                    <div className="flex items-center justify-between shrink-0 h-16 mt-2">
                        <button onClick={() => setFullScreen(false)} className="p-2 -ml-2 hover:bg-white/10 rounded-full active:scale-95 transition-transform">
                            <ChevronDown size={28} className="text-white" />
                        </button>
                        <div className="flex flex-col items-center opacity-80">
                            <span className="text-[10px] font-bold tracking-[0.2em] uppercase text-white/60">
                                {isOfflineMode ? "Offline Mode" : "Now Playing"}
                            </span>
                        </div>
                        <button className="p-2 -mr-2 hover:bg-white/10 rounded-full active:scale-95 transition-transform">
                            <MoreHorizontal size={24} className="text-white" />
                        </button>
                    </div>

                    {/* Album Art (Shared ID - Morphs position) */}
                    <div className="flex-1 flex items-center justify-center py-4 min-h-0">
                         <div className="relative w-full max-w-[340px] aspect-square">
                            <motion.img 
                                layoutId="player-image"
                                src={imageUrl} 
                                alt={currentSong.name} 
                                className="w-full h-full object-cover rounded-xl shadow-[0_8px_40px_rgba(0,0,0,0.5)]"
                                transition={transitionConfig}
                            />
                         </div>
                    </div>

                    {/* Track Info */}
                    <div className="flex flex-col gap-6 shrink-0 w-full max-w-lg mx-auto mb-6 md:mb-10">
                        <div className="flex items-center justify-between">
                            <div className="flex flex-col overflow-hidden mr-6 flex-1">
                                <motion.h1 
                                    initial={{ opacity: 0, x: -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ delay: 0.2 }}
                                    className="text-2xl md:text-3xl font-bold text-white whitespace-nowrap overflow-hidden text-ellipsis"
                                >
                                    {currentSong.name}
                                </motion.h1>
                                <motion.div 
                                    initial={{ opacity: 0, x: -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ delay: 0.3 }}
                                    className="flex items-center gap-2 mt-1"
                                >
                                    <p className="text-white/60 text-lg md:text-xl truncate font-medium">
                                        {primaryArtistName}
                                    </p>
                                    {isDownloaded && <CheckCircle2 size={16} className="text-[#1DB954]" />}
                                </motion.div>
                            </div>
                            <button onClick={() => toggleLike(currentSong)} className="transition-transform active:scale-75 shrink-0">
                                {isLiked ? <CheckCircle2 size={32} className="text-[#1DB954] fill-[#1DB954] text-black" /> : <PlusCircle size={32} className="text-white/60" />}
                            </button>
                        </div>

                        {/* Controls */}
                        <motion.div 
                            initial={{ opacity: 0, y: 20 }} 
                            animate={{ opacity: 1, y: 0 }} 
                            transition={{ delay: 0.2, duration: 0.3 }}
                            className="flex flex-col gap-2 pt-2"
                        >
                            {/* Scrubber */}
                            <div className="relative h-1 w-full bg-white/20 rounded-full group hover:h-1.5 transition-all">
                                 <div className="absolute left-0 top-0 bottom-0 bg-white rounded-full" style={{ width: `${(progress / (duration || 1)) * 100}%` }}>
                                    <div className="absolute right-0 top-1/2 -translate-y-1/2 w-3 h-3 bg-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity"></div>
                                 </div>
                                 <input 
                                    type="range" min="0" max={duration || 100} value={progress}
                                    onChange={handleSeek} onTouchStart={handleSeekStart} onTouchEnd={handleSeekEnd}
                                    onMouseDown={handleSeekStart} onMouseUp={handleSeekEnd}
                                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                                />
                            </div>
                            <div className="flex justify-between text-[11px] text-white/40 font-bold font-mono">
                                <span>{formatTime(progress)}</span>
                                <span>{formatTime(duration)}</span>
                            </div>

                            {/* Buttons */}
                            <div className="flex items-center justify-between -mx-2 mt-4">
                                <button className={`p-2 ${isShuffling ? 'text-[#1DB954]' : 'text-white/40'}`}><Shuffle size={20} /></button>

                                <div className="flex items-center gap-6 md:gap-10">
                                    <button onClick={prevSong} className="text-white hover:text-white/70 active:scale-90 transition-transform"><SkipBack size={32} fill="currentColor" /></button>
                                    <button 
                                        onClick={togglePlay}
                                        disabled={isBuffering}
                                        className="bg-white text-black rounded-full w-16 h-16 flex items-center justify-center hover:scale-105 active:scale-90 transition-all shadow-md"
                                    >
                                        {isBuffering ? <Loader2 size={32} className="animate-spin" /> : isPlaying ? <Pause size={32} fill="currentColor" /> : <Play size={32} fill="currentColor" className="ml-1" />}
                                    </button>
                                    <button onClick={nextSong} className="text-white hover:text-white/70 active:scale-90 transition-transform"><SkipForward size={32} fill="currentColor" /></button>
                                </div>

                                <button className="p-2 text-white/40"><Repeat size={20} /></button>
                            </div>
                        </motion.div>
                    </div>

                    {/* Bottom Actions */}
                    <motion.div 
                        initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 0.3 }}
                        className="flex items-center justify-between px-2"
                    >
                         <button 
                            onClick={() => setDownloadSong(currentSong)} 
                            className={`${isDownloaded ? 'text-[#1DB954]' : 'text-white/50 hover:text-white'}`}
                        >
                            <Download size={22} fill={isDownloaded ? "#1DB954" : "none"} />
                        </button>
                        <div className="flex items-center gap-6">
                            <button className="text-white/50 hover:text-white"><Mic2 size={22} /></button>
                            <button className="text-white/50 hover:text-white"><ListMusic size={24} /></button>
                        </div>
                    </motion.div>
                </div>
            </motion.div>
        ) : (
            /* --- MINI PLAYER --- */
            <motion.div 
                key="mini-player"
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0 }}
                onClick={() => setFullScreen(true)}
                className="fixed bottom-[68px] md:bottom-4 left-2 right-2 md:left-[50%] md:right-auto md:translate-x-[-50%] md:w-[450px] h-[56px] bg-[#222] border-t border-white/10 rounded-lg flex items-center pr-4 pl-2 shadow-2xl z-[150] cursor-pointer overflow-hidden"
            >
                {/* Image (Shared ID - Morphs position) */}
                <div className="relative h-10 w-10 shrink-0 mr-3">
                    <motion.img 
                        layoutId="player-image"
                        src={imageUrl} 
                        alt="cover" 
                        className="h-full w-full object-cover rounded-md" 
                        transition={transitionConfig}
                    />
                </div>

                {/* Text */}
                <div className="flex-1 min-w-0 flex flex-col justify-center mr-2">
                    <div className="flex items-center gap-1.5">
                        <span className={`text-white font-bold text-sm truncate ${isPlaying ? 'text-[#1DB954]' : ''}`}>
                            {currentSong.name}
                        </span>
                        {isDownloaded && isOfflineMode && <CheckCircle2 size={12} className="text-[#1DB954]" />}
                    </div>
                    <span className="text-white/70 text-xs truncate">
                        {primaryArtistName}
                    </span>
                </div>

                {/* Mini Controls */}
                <div className="flex items-center gap-3">
                     <button onClick={(e) => { e.stopPropagation(); toggleLike(currentSong); }} className="text-white/40 hover:text-[#1DB954] hidden sm:block">
                        <Heart size={20} fill={isLiked ? "#1DB954" : "transparent"} className={isLiked ? "text-[#1DB954]" : ""} />
                     </button>
                     <button onClick={(e) => { e.stopPropagation(); togglePlay(); }} className="text-white h-8 w-8 flex items-center justify-center">
                        {isBuffering ? <Loader2 size={20} className="animate-spin text-white/70" /> : isPlaying ? <Pause size={20} fill="currentColor" /> : <Play size={20} fill="currentColor" />}
                     </button>
                </div>

                 {/* Progress Bar Line */}
                <div className="absolute bottom-0 left-0 right-0 h-[2px] bg-white/10 pointer-events-none">
                     <div className="h-full bg-white rounded-r-full transition-all duration-300 ease-linear" style={{ width: `${(progress / (duration || 1)) * 100}%` }}></div>
                </div>
            </motion.div>
        )}
        </AnimatePresence>

        {downloadSong && (
            <DownloadQualityModal song={downloadSong} onClose={() => setDownloadSong(null)} />
        )}
    </>
  );
};

