  { title: "Student", color: "bg-[#AF2896]" },
  { title: "Chill", color: "bg-[#D84000]" },
  { title: "Gaming", color: "bg-[#E8115B]" },
  { title: "K-Pop", color: "bg-[#148A08]" },
];

const containerVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: {
      staggerChildren: 0.05
    }
  }
};

const itemVariants = {
  hidden: { opacity: 0, scale: 0.9 },
  visible: { opacity: 1, scale: 1 }
};

export const Search: React.FC = () => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<{ songs: Song[], albums: Album[], artists: Artist[] }>({ songs: [], albums: [], artists: [] });
  const [isLoading, setIsLoading] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [isFocused, setIsFocused] = useState(false);

  const { playSong, likedSongs, toggleLike } = usePlayerStore();
  const navigate = useNavigate();

  // AbortController to handle race conditions
  const abortControllerRef = useRef<AbortController | null>(null);

  useEffect(() => {
    // Cancel any ongoing fetch if query changes
    if (abortControllerRef.current) {
        abortControllerRef.current.abort();
    }

    if (!query.trim()) {
        setResults({ songs: [], albums: [], artists: [] });
        setSuggestions([]);
        setIsLoading(false);
        return;
    }

    setIsLoading(true);

    const timer = setTimeout(async () => {
        abortControllerRef.current = new AbortController();
        try {
           const [songs, albums, artists] = await Promise.all([
              api.searchSongs(query),
              api.searchAlbums(query),
              api.searchArtists(query)
           ]);

           // Only update if not aborted
           if (!abortControllerRef.current?.signal.aborted) {
               setResults({ songs, albums, artists });

               // Generate Related Keywords from results
               const rawTitles = songs.map(s => s.name.toLowerCase());
               const artistNames = artists.slice(0, 2).map(a => a.name.toLowerCase());

               const derivedSuggestions = Array.from(new Set([
                   query.toLowerCase(), 
                   ...rawTitles.filter(t => t.includes(query.toLowerCase()) && t !== query.toLowerCase()),
                   ...artistNames,
                   ...rawTitles
               ])).slice(0, 4); 

               setSuggestions(derivedSuggestions);
           }
        } catch (e: any) {
            if (e.name !== 'AbortError') {
                console.error(e);
            }
        } finally {
            if (!abortControllerRef.current?.signal.aborted) {
                setIsLoading(false);
            }
        }
    }, 300);

    return () => clearTimeout(timer);
  }, [query]);

  const clearSearch = () => {
    setQuery('');
    setResults({ songs: [], albums: [], artists: [] });
    setSuggestions([]);
    setIsLoading(false);
  };

  const ResultSkeleton = () => (
      <div className="flex items-center gap-3 px-4 py-2.5 animate-pulse">
          <div className="w-12 h-12 bg-white/10 rounded-md shrink-0"></div>
          <div className="flex-1 space-y-2 py-1">
              <div className="h-4 bg-white/10 rounded w-1/3"></div>
              <div className="h-3 bg-white/5 rounded w-1/4"></div>
          </div>
      </div>
  );

  return (
    <div className="flex flex-col min-h-full pb-32 bg-black">

      {/* Search Header */}
      <div className="sticky top-0 bg-[#121212] z-30 px-4 py-3 border-b border-white/5 transition-colors duration-300">
         <div className="flex items-center gap-3">
             <button onClick={() => navigate(-1)} className="text-white hover:bg-white/10 p-2 rounded-full transition-colors active:scale-95 md:hidden">
                <ArrowLeft size={24} />
             </button>

             {/* Premium Search Bar */}
             <div className={`flex-1 relative group transition-all duration-300 ease-out ${isFocused ? 'scale-[1.01]' : 'scale-100'}`}>
                {/* Search Icon */}
                <div className={`absolute inset-y-0 left-3.5 flex items-center pointer-events-none transition-colors duration-300 ${isFocused ? 'text-white' : 'text-[#777]'}`}>
                     <SearchIcon size={20} />
                </div>

                {/* Input Field */}
                <input 
                  type="text"
                  className="w-full bg-[#242424] hover:bg-[#2a2a2a] focus:bg-[#1f1f1f] text-white rounded-full py-3 pl-11 pr-11 outline-none border border-transparent focus:border-white/10 focus:shadow-[0_0_20px_rgba(255,255,255,0.03)] placeholder-[#777] font-medium text-[16px] transition-all duration-300 ease-out"
                  placeholder="What do you want to listen to?"
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                  onFocus={() => setIsFocused(true)}
                  onBlur={() => setIsFocused(false)}
                  autoFocus={false}
                />

                {/* Clear / Loading Action */}
                {(query || isLoading) && (
                    <div className="absolute right-3.5 top-1/2 -translate-y-1/2 flex items-center">
                         {isLoading ? (
                             <Loader2 size={18} className="text-[#1DB954] animate-spin" />
                         ) : (
                             <button onClick={clearSearch} className="text-[#777] hover:text-white p-1 rounded-full hover:bg-white/10 transition-colors">
                                 <X size={18} />
                             </button>
                         )}
                    </div>
                )}
             </div>
         </div>
      </div>

      {/* Browse All (Initial State) */}
      {!query && (
         <div className="p-4">
             <h2 className="text-white font-bold text-lg mb-4">Browse all</h2>
             <motion.div 
                variants={containerVariants}
                initial="hidden"
                animate="visible"
                className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-4"
             >
                 {BROWSE_CATEGORIES.map((cat, idx) => (
                     <motion.div 
                        key={idx} 
                        variants={itemVariants}
                        whileHover={{ scale: 1.02 }}
                        whileTap={{ scale: 0.98 }}
                        className={`${cat.color} aspect-[1.6/1] rounded-lg p-4 relative overflow-hidden cursor-pointer hover:opacity-90 transition-opacity`}
                        onClick={() => setQuery(cat.title)} 
                     >
                         <h3 className="text-white font-bold text-xl md:text-2xl break-words max-w-[80%] relative z-10 leading-tight">
                            {cat.title}
                         </h3>
                         <div className="absolute -bottom-2 -right-4 w-20 h-20 bg-black/20 rotate-[25deg] shadow-lg rounded-md flex items-center justify-center">
                         </div>
                     </motion.div>
                 ))}
             </motion.div>
         </div>
      )}

      {/* Loading State Skeleton */}
      {isLoading && !results.songs.length && (
          <div className="flex flex-col w-full pt-2">
              {[1,2,3,4,5].map(i => <ResultSkeleton key={i} />)}
          </div>
      )}

      {/* Results */}
      {query && (
        <div className="flex flex-col w-full pb-8">

            {/* 1. Related Keywords (Suggestions) */}
            {suggestions.length > 0 && (
                <div className="flex flex-col mb-2">
                    {suggestions.map((suggestion, idx) => (
                        <div 
                            key={idx}
                            onClick={() => setQuery(suggestion)}
                            className="flex items-center justify-between px-4 py-3.5 hover:bg-[#1A1A1A] active:bg-[#222] cursor-pointer transition-colors border-b border-white/5 last:border-0"
                        >
                            <div className="flex items-center gap-4">
                                <SearchIcon size={20} className="text-[#B3B3B3]" />
                                <span className="text-white text-[15px]">{suggestion}</span>
                            </div>
                            <ArrowUpLeft size={18} className="text-[#555] rotate-45" />
                        </div>
                    ))}
                </div>
            )}

            {/* 2. Songs List */}
            {results.songs.length > 0 && (
                <div className="animate-in fade-in slide-in-from-bottom-3 duration-300 delay-75">
                     {/* REMOVED SLICE TO SHOW ALL SONGS */}
                     {results.songs.map((song) => {
                         const isLiked = likedSongs.some(s => s.id === song.id);
                         const artistName = song.artists?.primary?.[0]?.name || "Unknown";

                         return (
                             <div 
                                key={song.id} 
                                className="flex items-center gap-3 px-4 py-2 hover:bg-[#1A1A1A] cursor-pointer group transition-colors" 
                                onClick={() => playSong(song, results.songs)}
                             >
                                 <div className="w-12 h-12 shrink-0 relative">
                                    <img src={getImageUrl(song.image)} className="w-full h-full rounded-[4px] object-cover" alt="" />
                                 </div>
                                 <div className="flex-1 min-w-0 flex flex-col justify-center gap-0.5">
                                     <div className={`font-medium truncate text-[16px] text-white ${isLiked ? 'text-[#1DB954]' : ''}`}>{song.name}</div>
                                     <div className="text-[#B3B3B3] text-sm truncate flex items-center gap-1">
                                        {song.name.toLowerCase().includes('explicit') && (
                                            <span className="bg-[#B3B3B3] text-black text-[9px] px-1 rounded-[2px] font-bold">E</span>
                                        )}
                                        <span>Song • {artistName}</span>
                                     </div>
                                 </div>

                                 <div className="flex items-center gap-4">
                                     <button 
                                        className="text-[#B3B3B3] hover:text-white transition-transform active:scale-90" 
                                        onClick={(e) => { e.stopPropagation(); toggleLike(song); }}
                                     >
                                        {isLiked ? (
                                            <CheckCircle2 size={22} className="text-[#1DB954] fill-[#1DB954] text-black" />
                                        ) : (
                                            <PlusCircle size={22} />
                                        )}
                                     </button>
                                     <button className="text-[#B3B3B3] hover:text-white" onClick={(e) => e.stopPropagation()}>
                                         <MoreVertical size={20} />
                                     </button>
                                 </div>
                             </div>
                         );
                     })}
                </div>
            )}

            {/* No Results */}
            {!isLoading && results.songs.length === 0 && suggestions.length === 0 && (
                <div className="flex flex-col items-center justify-center pt-20 text-[#777]">
                    <div className="w-20 h-20 bg-[#1A1A1A] rounded-full flex items-center justify-center mb-4">
                        <SearchIcon size={40} className="opacity-50"/>
                    </div>
                    <h3 className="text-white font-bold text-lg">No results found</h3>
                    <p className="text-sm mt-2">Try searching for a different song or artist.</p>
                </div>
            )}
        </div>
      )}
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { Play, Pause, SkipBack, SkipForward, ChevronDown, MoreHorizontal, Download, ListMusic, Heart, Loader2, Shuffle, Repeat, Mic2, PlusCircle, CheckCircle2, Disc, User, Share2, ListPlus, X, Check, ChevronLeft } from 'lucide-react';
import { usePlayerStore } from '../store/playerStore';
import { getImageUrl, getAudioUrl, getOfflineAudioUrl } from '../services/api';
import { AnimatePresence, motion } from 'framer-motion';
import { DownloadQualityModal } from './DownloadQualityModal';
import { Song } from '../types';
import { useNavigate } from 'react-router-dom';

export const Player: React.FC = () => {
  const { 
    currentSong, 
    isPlaying, 
    isBuffering,
    isFullScreen,
    setFullScreen,
    togglePlay, 
    setIsPlaying, 
    setIsBuffering,
    nextSong, 
    prevSong,
    likedSongs,
    toggleLike,
    isShuffling,
    streamingQuality,
    isOfflineMode,
    downloadedSongIds,
    userPlaylists,
    addSongToPlaylist
  } = usePlayerStore();

  const navigate = useNavigate();
  const audioRef = useRef<HTMLAudioElement>(null);
  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);
  const [dominantColor, setDominantColor] = useState<string>('#121212');
  const [isDragging, setIsDragging] = useState(false);

  // Modals state
  const [downloadSong, setDownloadSong] = useState<Song | null>(null);
  const [isMoreMenuOpen, setIsMoreMenuOpen] = useState(false);
  const [showPlaylistSelector, setShowPlaylistSelector] = useState(false);

  const [touchStart, setTouchStart] = useState<{x: number, y: number} | null>(null);

  const isLiked = currentSong ? likedSongs.some(s => s.id === currentSong.id) : false;
  const isDownloaded = currentSong ? downloadedSongIds.includes(currentSong.id) : false;

  useEffect(() => {
    if (!currentSong) return;

    const imgUrl = getImageUrl(currentSong.image);
    const img = new Image();
    img.crossOrigin = "Anonymous";
    img.src = imgUrl;

    img.onload = () => {
      try {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) return;
        canvas.width = 1;
        canvas.height = 1;
        ctx.drawImage(img, 0, 0, 1, 1);
        const [r, g, b] = ctx.getImageData(0, 0, 1, 1).data;
        setDominantColor(`rgb(${r},${g},${b})`);
      } catch (e) {
        setDominantColor('#2a2a2a'); 
      }
    };
    img.onerror = () => setDominantColor('#2a2a2a');
  }, [currentSong?.id]);

  useEffect(() => {
    if (!currentSong || !audioRef.current) return;

    const setAudioSource = async () => {
        let url = '';

        // OFFLINE LOGIC: If offline mode OR song is known to be downloaded, try IDB first
        if (isOfflineMode || downloadedSongIds.includes(currentSong.id)) {
            const blobUrl = await getOfflineAudioUrl(currentSong.id);
            if (blobUrl) {
                url = blobUrl;
                console.log("Playing from Offline Storage");
            } else if (isOfflineMode) {
                console.warn("Song not available offline");
                setIsPlaying(false);
                return;
            }
        }

        // Fallback to Network if no offline blob found and we are Online
        if (!url && !isOfflineMode) {
             url = getAudioUrl(currentSong.downloadUrl, streamingQuality);
        }

        if (url && audioRef.current && audioRef.current.src !== url) {
            const wasPlaying = isPlaying;
            audioRef.current.src = url;
            audioRef.current.load();
            if (wasPlaying) {
                 const playPromise = audioRef.current.play();
                 if (playPromise !== undefined) {
                     playPromise.catch(error => {
                         console.warn("Autoplay prevented:", error);
                         setIsPlaying(false);
                     });
                 }
            }
        }
    };

    setAudioSource();

    return () => {
        if (audioRef.current?.src.startsWith('blob:')) {
            URL.revokeObjectURL(audioRef.current.src);
        }
    };
  }, [currentSong?.id, streamingQuality, isOfflineMode, downloadedSongIds]);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;
    if (isPlaying && audio.paused) audio.play().catch(e => console.warn("Play interrupted", e));
    else if (!isPlaying && !audio.paused) audio.pause();
  }, [isPlaying]);

  const handleTimeUpdate = () => {
    if (audioRef.current && !isDragging) {
      setProgress(audioRef.current.currentTime);
      setDuration(audioRef.current.duration || 0);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);
    setProgress(time);
    if (audioRef.current) audioRef.current.currentTime = time;
  };

  const handleSeekStart = () => setIsDragging(true);
  const handleSeekEnd = () => {
      setIsDragging(false);
       if (audioRef.current) audioRef.current.currentTime = progress;
  };

  const formatTime = (seconds: number) => {
    if (!seconds || isNaN(seconds)) return "-:--";
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    setTouchStart({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY });
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (!touchStart) return;
    const touchEndX = e.changedTouches[0].clientX;
    const touchEndY = e.changedTouches[0].clientY;
    const diffX = touchStart.x - touchEndX;
    const diffY = touchStart.y - touchEndY;

    if (Math.abs(diffX) > 50 && Math.abs(diffX) > Math.abs(diffY)) {
      if (diffX > 0) nextSong();
      else prevSong();
    }

    // Swipe Down to close (only if menu is not open)
    if (diffY < -80 && Math.abs(diffY) > Math.abs(diffX) && !isMoreMenuOpen) {
        setFullScreen(false);
    }
    setTouchStart(null);
  };

  // --- ACTIONS ---
  const handleViewArtist = () => {
      if (!currentSong) return;
      setFullScreen(false);
      setIsMoreMenuOpen(false);
      navigate(`/artist/${currentSong.artists.primary[0].id}`, { 
          state: { artist: currentSong.artists.primary[0] } 
      });
  };

  const handleViewAlbum = () => {
      if (!currentSong) return;
      setFullScreen(false);
      setIsMoreMenuOpen(false);
      navigate(`/album/${currentSong.album.id}`);
  };

  const handleShare = () => {
      // Simulate share
      const url = window.location.href;
      navigator.clipboard.writeText(url);
      alert("Link copied to clipboard!");
      setIsMoreMenuOpen(false);
  };

  const handleAddToPlaylist = (playlistId: string) => {
      if (!currentSong) return;
      addSongToPlaylist(playlistId, currentSong);
      setShowPlaylistSelector(false);
      setIsMoreMenuOpen(false);
  };

  if (!currentSong) return null;

  const imageUrl = getImageUrl(currentSong.image);
  const primaryArtistName = currentSong.artists?.primary?.[0]?.name || currentSong.artists?.all?.[0]?.name || "Unknown Artist";

  const transitionConfig = {
    type: "spring",
    stiffness: 280,
    damping: 28,
    mass: 0.8
  };

  return (
    <>
        <audio 
            ref={audioRef}
            preload="auto"
            onTimeUpdate={handleTimeUpdate}
            onEnded={nextSong}
            onWaiting={() => setIsBuffering(true)}
            onPlaying={() => setIsBuffering(false)}
            onCanPlay={() => setIsBuffering(false)}
            onPause={() => {
                if (isPlaying && !isBuffering && audioRef.current?.paused && audioRef.current?.readyState > 2) setIsPlaying(false);
            }}
            onPlay={() => !isPlaying && setIsPlaying(true)}
            onError={() => { setIsBuffering(false); setIsPlaying(false); }}
        />

        <AnimatePresence mode="wait"> 
        {isFullScreen ? (
            /* --- FULL PLAYER --- */
            <motion.div 
                key="full-player"
                initial={{ y: "100%" }}
                animate={{ y: 0 }}
                exit={{ y: "100%" }}
                transition={{ 
                   type: "spring", 
                   stiffness: 250, 
                   damping: 25,
                   mass: 0.8
                }}
                className="fixed inset-0 z-[200] flex flex-col bg-[#121212] overflow-hidden font-sans touch-none"
                onClick={(e) => e.stopPropagation()}
                onTouchStart={handleTouchStart}
                onTouchEnd={handleTouchEnd}
            >
                {/* Dynamic Background */}
                <div 
                    className="absolute inset-0 z-0 pointer-events-none transition-colors duration-700 ease-in-out"
                    style={{ background: `linear-gradient(to bottom, ${dominantColor}, #121212)` }}
                />

                <div className="relative z-10 flex flex-col h-full text-white px-6 pb-8 pt-safe-top md:px-12 md:pb-12">

                    {/* Header */}
                    <div className="flex items-center justify-between shrink-0 h-16 mt-2">
                        <button onClick={() => setFullScreen(false)} className="p-2 -ml-2 hover:bg-white/10 rounded-full active:scale-95 transition-transform">
                            <ChevronDown size={28} className="text-white" />
                        </button>
                        <div className="flex flex-col items-center opacity-80">
                            <span className="text-[10px] font-bold tracking-[0.2em] uppercase text-white/60">
                                {isOfflineMode ? "Offline Mode" : "Now Playing"}
                            </span>
                        </div>
                        <button 
                            onClick={() => { setShowPlaylistSelector(false); setIsMoreMenuOpen(true); }}
                            className="p-2 -mr-2 hover:bg-white/10 rounded-full active:scale-95 transition-transform"
                        >
                            <MoreHorizontal size={24} className="text-white" />
                        </button>
                    </div>

                    {/* Album Art (Shared ID - Morphs position) */}
                    <div className="flex-1 flex items-center justify-center py-4 min-h-0">
                         <div className="relative w-full max-w-[340px] aspect-square">
                            <motion.img 
                                layoutId="player-image"
                                src={imageUrl} 
                                alt={currentSong.name} 
                                className="w-full h-full object-cover rounded-xl shadow-[0_8px_40px_rgba(0,0,0,0.5)]"
                                transition={transitionConfig}
                            />
                         </div>
                    </div>

                    {/* Track Info */}
                    <div className="flex flex-col gap-6 shrink-0 w-full max-w-lg mx-auto mb-6 md:mb-10">
                        <div className="flex items-center justify-between">
                            <div className="flex flex-col overflow-hidden mr-6 flex-1">
                                <motion.h1 
                                    initial={{ opacity: 0, x: -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ delay: 0.2 }}
                                    className="text-2xl md:text-3xl font-bold text-white whitespace-nowrap overflow-hidden text-ellipsis"
                                >
                                    {currentSong.name}
                                </motion.h1>
                                <motion.div 
                                    initial={{ opacity: 0, x: -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ delay: 0.3 }}
                                    className="flex items-center gap-2 mt-1"
                                >
                                    <p className="text-white/60 text-lg md:text-xl truncate font-medium">
                                        {primaryArtistName}
                                    </p>
                                    {isDownloaded && <CheckCircle2 size={16} className="text-[#1DB954]" />}
                                </motion.div>
                            </div>
                            <button onClick={() => toggleLike(currentSong)} className="transition-transform active:scale-75 shrink-0">
                                {isLiked ? <CheckCircle2 size={32} className="text-[#1DB954] fill-[#1DB954] text-black" /> : <PlusCircle size={32} className="text-white/60" />}
                            </button>
                        </div>

                        {/* Controls */}
                        <motion.div 
                            initial={{ opacity: 0, y: 20 }} 
                            animate={{ opacity: 1, y: 0 }} 
                            transition={{ delay: 0.2, duration: 0.3 }}
                            className="flex flex-col gap-2 pt-2"
                        >
                            {/* Scrubber */}
                            <div className="relative h-1 w-full bg-white/20 rounded-full group hover:h-1.5 transition-all">
                                 <div className="absolute left-0 top-0 bottom-0 bg-white rounded-full" style={{ width: `${(progress / (duration || 1)) * 100}%` }}>
                                    <div className="absolute right-0 top-1/2 -translate-y-1/2 w-3 h-3 bg-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity"></div>
                                 </div>
                                 <input 
                                    type="range" min="0" max={duration || 100} value={progress}
                                    onChange={handleSeek} onTouchStart={handleSeekStart} onTouchEnd={handleSeekEnd}
                                    onMouseDown={handleSeekStart} onMouseUp={handleSeekEnd}
                                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                                />
                            </div>
                            <div className="flex justify-between text-[11px] text-white/40 font-bold font-mono">
                                <span>{formatTime(progress)}</span>
                                <span>{formatTime(duration)}</span>
                            </div>

                            {/* Buttons */}
                            <div className="flex items-center justify-between -mx-2 mt-4">
                                <button className={`p-2 ${isShuffling ? 'text-[#1DB954]' : 'text-white/40'}`}><Shuffle size={20} /></button>

                                <div className="flex items-center gap-6 md:gap-10">
                                    <button onClick={prevSong} className="text-white hover:text-white/70 active:scale-90 transition-transform"><SkipBack size={32} fill="currentColor" /></button>
                                    <button 
                                        onClick={togglePlay}
                                        disabled={isBuffering}
                                        className="bg-white text-black rounded-full w-16 h-16 flex items-center justify-center hover:scale-105 active:scale-90 transition-all shadow-md"
                                    >
                                        {isBuffering ? <Loader2 size={32} className="animate-spin" /> : isPlaying ? <Pause size={32} fill="currentColor" /> : <Play size={32} fill="currentColor" className="ml-1" />}
                                    </button>
                                    <button onClick={nextSong} className="text-white hover:text-white/70 active:scale-90 transition-transform"><SkipForward size={32} fill="currentColor" /></button>
                                </div>

                                <button className="p-2 text-white/40"><Repeat size={20} /></button>
                            </div>
                        </motion.div>
                    </div>

                    {/* Bottom Actions */}
                    <motion.div 
                        initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 0.3 }}
                        className="flex items-center justify-between px-2"
                    >
                         <button 
                            onClick={() => setDownloadSong(currentSong)} 
                            className={`${isDownloaded ? 'text-[#1DB954]' : 'text-white/50 hover:text-white'}`}
                        >
                            <Download size={22} fill={isDownloaded ? "#1DB954" : "none"} />
                        </button>
                        <div className="flex items-center gap-6">
                            <button className="text-white/50 hover:text-white"><Mic2 size={22} /></button>
                            <button className="text-white/50 hover:text-white"><ListMusic size={24} /></button>
                        </div>
                    </motion.div>
                </div>

                {/* --- MORE OPTIONS MENU OVERLAY --- */}
                <AnimatePresence>
                    {isMoreMenuOpen && (
                        <motion.div 
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            className="absolute inset-0 z-[250] bg-black/60 backdrop-blur-sm flex flex-col justify-end"
                            onClick={() => setIsMoreMenuOpen(false)}
                        >
                            <motion.div 
                                initial={{ y: "100%" }}
                                animate={{ y: 0 }}
                                exit={{ y: "100%" }}
                                transition={{ type: "spring", damping: 25, stiffness: 300 }}
                                className="bg-[#1E1E1E] rounded-t-2xl overflow-hidden max-h-[70vh] flex flex-col"
                                onClick={(e) => e.stopPropagation()}
                            >
                                {/* Dragger */}
                                <div className="w-full flex justify-center pt-3 pb-1">
                                    <div className="w-10 h-1 bg-white/20 rounded-full"></div>
                                </div>

                                {!showPlaylistSelector ? (
                                    /* MAIN MENU */
                                    <div className="p-4 flex flex-col gap-2">
                                        <div className="flex items-center gap-3 p-2 mb-2 border-b border-white/10 pb-4">
                                            <img src={imageUrl} className="w-12 h-12 rounded-md object-cover" alt="" />
                                            <div className="flex flex-col">
                                                <span className="font-bold text-white text-sm">{currentSong.name}</span>
                                                <span className="text-xs text-[#B3B3B3]">{primaryArtistName}</span>
                                            </div>
                                        </div>

                                        <button 
                                            onClick={() => setShowPlaylistSelector(true)}
                                            className="flex items-center gap-4 p-3 hover:bg-white/5 rounded-lg text-white font-medium transition-colors"
                                        >
                                            <ListPlus size={22} className="text-[#B3B3B3]" /> Add to Playlist
                                        </button>
                                        <button 
                                            onClick={handleViewArtist}
                                            className="flex items-center gap-4 p-3 hover:bg-white/5 rounded-lg text-white font-medium transition-colors"
                                        >
                                            <User size={22} className="text-[#B3B3B3]" /> View Artist
                                        </button>
                                        <button 
                                            onClick={handleViewAlbum}
                                            className="flex items-center gap-4 p-3 hover:bg-white/5 rounded-lg text-white font-medium transition-colors"
                                        >
                                            <Disc size={22} className="text-[#B3B3B3]" /> View Album
                                        </button>
                                        <button 
                                            onClick={handleShare}
                                            className="flex items-center gap-4 p-3 hover:bg-white/5 rounded-lg text-white font-medium transition-colors"
                                        >
                                            <Share2 size={22} className="text-[#B3B3B3]" /> Share
                                        </button>

                                        <div className="p-2 mt-2">
                                            <button onClick={() => setIsMoreMenuOpen(false)} className="w-full py-3 rounded-full font-bold text-white/50 hover:text-white">
                                                Cancel
                                            </button>
                                        </div>
                                    </div>
                                ) : (
                                    /* PLAYLIST SELECTOR */
                                    <div className="flex flex-col h-full">
                                        <div className="flex items-center gap-2 p-4 border-b border-white/10">
                                            <button onClick={() => setShowPlaylistSelector(false)} className="p-1">
                                                <ChevronLeft size={24} />
                                            </button>
                                            <span className="font-bold text-white">Add to playlist</span>
                                        </div>

                                        <div className="overflow-y-auto max-h-[400px] p-2">
                                            <button 
                                                className="flex items-center gap-3 p-3 w-full hover:bg-white/5 rounded-lg mb-2"
                                                onClick={() => { /* Open Create Modal logic if needed, simplify for now */ }}
                                            >
                                                <div className="w-12 h-12 bg-[#2A2A2A] flex items-center justify-center rounded-md">
                                                    <PlusCircle size={24} className="text-white" />
                                                </div>
                                                <span className="font-bold text-white">New Playlist</span>
                                            </button>

                                            {userPlaylists.map(pl => {
                                                const isAdded = pl.songs.some(s => s.id === currentSong.id);
                                                return (
                                                    <button 
                                                        key={pl.id}
                                                        onClick={() => !isAdded && handleAddToPlaylist(pl.id)}
                                                        className="flex items-center justify-between p-3 w-full hover:bg-white/5 rounded-lg"
                                                        disabled={isAdded}
                                                    >
                                                        <div className="flex items-center gap-3">
                                                            <div className="w-12 h-12 bg-[#333] rounded-md overflow-hidden">
                                                                {pl.image?.[0] ? <img src={getImageUrl(pl.image)} className="w-full h-full object-cover" alt=""/> : <ListMusic className="m-auto mt-3 text-white/50" />}
                                                            </div>
                                                            <div className="flex flex-col text-left">
                                                                <span className={`font-bold text-sm ${isAdded ? 'text-[#1DB954]' : 'text-white'}`}>{pl.title}</span>
                                                                <span className="text-xs text-[#777]">{pl.songs.length} songs</span>
                                                            </div>
                                                        </div>
                                                        {isAdded && <Check size={20} className="text-[#1DB954]" />}
                                                    </button>
                                                )
                                            })}
                                        </div>
                                    </div>
                                )}
                            </motion.div>
                        </motion.div>
                    )}
                </AnimatePresence>

            </motion.div>
        ) : (
            /* --- MINI PLAYER --- */
            <motion.div 
                key="mini-player"
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0 }}
                onClick={() => setFullScreen(true)}
                className="fixed bottom-[68px] md:bottom-4 left-2 right-2 md:left-[50%] md:right-auto md:translate-x-[-50%] md:w-[450px] h-[56px] bg-[#222] border-t border-white/10 rounded-lg flex items-center pr-4 pl-2 shadow-2xl z-[150] cursor-pointer overflow-hidden"
            >
                {/* Image (Shared ID - Morphs position) */}
                <div className="relative h-10 w-10 shrink-0 mr-3">
                    <motion.img 
                        layoutId="player-image"
                        src={imageUrl} 
                        alt="cover" 
                        className="h-full w-full object-cover rounded-md" 
                        transition={transitionConfig}
                    />
                </div>

                {/* Text */}
                <div className="flex-1 min-w-0 flex flex-col justify-center mr-2">
                    <div className="flex items-center gap-1.5">
                        <span className={`text-white font-bold text-sm truncate ${isPlaying ? 'text-[#1DB954]' : ''}`}>
                            {currentSong.name}
                        </span>
                        {isDownloaded && isOfflineMode && <CheckCircle2 size={12} className="text-[#1DB954]" />}
                    </div>
                    <span className="text-white/70 text-xs truncate">
                        {primaryArtistName}
                    </span>
                </div>

                {/* Mini Controls */}
                <div className="flex items-center gap-3">
                     <button onClick={(e) => { e.stopPropagation(); toggleLike(currentSong); }} className="text-white/40 hover:text-[#1DB954] hidden sm:block">
                        <Heart size={20} fill={isLiked ? "#1DB954" : "transparent"} className={isLiked ? "text-[#1DB954]" : ""} />
                     </button>
                     <button onClick={(e) => { e.stopPropagation(); togglePlay(); }} className="text-white h-8 w-8 flex items-center justify-center">
                        {isBuffering ? <Loader2 size={20} className="animate-spin text-white/70" /> : isPlaying ? <Pause size={20} fill="currentColor" /> : <Play size={20} fill="currentColor" />}
                     </button>
                </div>

                 {/* Progress Bar Line */}
                <div className="absolute bottom-0 left-0 right-0 h-[2px] bg-white/10 pointer-events-none">
                     <div className="h-full bg-white rounded-r-full transition-all duration-300 ease-linear" style={{ width: `${(progress / (duration || 1)) * 100}%` }}></div>
                </div>
            </motion.div>
        )}
        </AnimatePresence>

        {downloadSong && (
            <DownloadQualityModal song={downloadSong} onClose={() => setDownloadSong(null)} />
        )}
    </>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { Play, Pause, SkipBack, SkipForward, ChevronDown, MoreHorizontal, Download, ListMusic, Heart, Loader2, Shuffle, Repeat, Mic2, PlusCircle, CheckCircle2, Disc, User, Share2, ListPlus, X, Check, ChevronLeft } from 'lucide-react';
import { usePlayerStore } from '../store/playerStore';
import { getImageUrl, getAudioUrl, getOfflineAudioUrl } from '../services/api';
import { AnimatePresence, motion } from 'framer-motion';
import { DownloadQualityModal } from './DownloadQualityModal';
import { Song } from '../types';
import { useNavigate } from 'react-router-dom';

export const Player: React.FC = () => {
  const { 
    currentSong, 
    isPlaying, 
    isBuffering,
    isFullScreen,
    setFullScreen,
    togglePlay, 
    setIsPlaying, 
    setIsBuffering,
    nextSong, 
    prevSong,
    likedSongs,
    toggleLike,
    isShuffling,
    streamingQuality,
    isOfflineMode,
    downloadedSongIds,
    userPlaylists,
    addSongToPlaylist
  } = usePlayerStore();

  const navigate = useNavigate();
  const audioRef = useRef<HTMLAudioElement>(null);
  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);
  const [dominantColor, setDominantColor] = useState<string>('#222222');
  const [isDragging, setIsDragging] = useState(false);

  // Modals state
  const [downloadSong, setDownloadSong] = useState<Song | null>(null);
  const [isMoreMenuOpen, setIsMoreMenuOpen] = useState(false);
  const [showPlaylistSelector, setShowPlaylistSelector] = useState(false);

  const [touchStart, setTouchStart] = useState<{x: number, y: number} | null>(null);

  const isLiked = currentSong ? likedSongs.some(s => s.id === currentSong.id) : false;
  const isDownloaded = currentSong ? downloadedSongIds.includes(currentSong.id) : false;

  useEffect(() => {
    if (!currentSong) return;

    const imgUrl = getImageUrl(currentSong.image);
    const img = new Image();
    img.crossOrigin = "Anonymous";
    img.src = imgUrl;

    img.onload = () => {
      try {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) return;
        canvas.width = 1;
        canvas.height = 1;
        ctx.drawImage(img, 0, 0, 1, 1);
        const [r, g, b] = ctx.getImageData(0, 0, 1, 1).data;
        setDominantColor(`rgb(${r},${g},${b})`);
      } catch (e) {
        setDominantColor('#222222'); 
      }
    };
    img.onerror = () => setDominantColor('#222222');
  }, [currentSong?.id]);

  useEffect(() => {
    if (!currentSong || !audioRef.current) return;

    const setAudioSource = async () => {
        let url = '';

        // OFFLINE LOGIC: If offline mode OR song is known to be downloaded, try IDB first
        if (isOfflineMode || downloadedSongIds.includes(currentSong.id)) {
            const blobUrl = await getOfflineAudioUrl(currentSong.id);
            if (blobUrl) {
                url = blobUrl;
                console.log("Playing from Offline Storage");
            } else if (isOfflineMode) {
                console.warn("Song not available offline");
                setIsPlaying(false);
                return;
            }
        }

        // Fallback to Network if no offline blob found and we are Online
        if (!url && !isOfflineMode) {
             url = getAudioUrl(currentSong.downloadUrl, streamingQuality);
        }

        if (url && audioRef.current && audioRef.current.src !== url) {
            const wasPlaying = isPlaying;
            audioRef.current.src = url;
            audioRef.current.load();
            if (wasPlaying) {
                 const playPromise = audioRef.current.play();
                 if (playPromise !== undefined) {
                     playPromise.catch(error => {
                         console.warn("Autoplay prevented:", error);
                         setIsPlaying(false);
                     });
                 }
            }
        }
    };

    setAudioSource();

    return () => {
        if (audioRef.current?.src.startsWith('blob:')) {
            URL.revokeObjectURL(audioRef.current.src);
        }
    };
  }, [currentSong?.id, streamingQuality, isOfflineMode, downloadedSongIds]);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;
    if (isPlaying && audio.paused) audio.play().catch(e => console.warn("Play interrupted", e));
    else if (!isPlaying && !audio.paused) audio.pause();
  }, [isPlaying]);

  const handleTimeUpdate = () => {
    if (audioRef.current && !isDragging) {
      setProgress(audioRef.current.currentTime);
      setDuration(audioRef.current.duration || 0);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);
    setProgress(time);
    if (audioRef.current) audioRef.current.currentTime = time;
  };

  const handleSeekStart = () => setIsDragging(true);
  const handleSeekEnd = () => {
      setIsDragging(false);
       if (audioRef.current) audioRef.current.currentTime = progress;
  };

  const formatTime = (seconds: number) => {
    if (!seconds || isNaN(seconds)) return "-:--";
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    setTouchStart({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY });
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (!touchStart) return;
    const touchEndX = e.changedTouches[0].clientX;
    const touchEndY = e.changedTouches[0].clientY;
    const diffX = touchStart.x - touchEndX;
    const diffY = touchStart.y - touchEndY;

    if (Math.abs(diffX) > 50 && Math.abs(diffX) > Math.abs(diffY)) {
      if (diffX > 0) nextSong();
      else prevSong();
    }

    // Swipe Down to close (only if menu is not open)
    if (diffY < -80 && Math.abs(diffY) > Math.abs(diffX) && !isMoreMenuOpen) {
        setFullScreen(false);
    }
    setTouchStart(null);
  };

  // --- ACTIONS ---
  const handleViewArtist = () => {
      if (!currentSong) return;
      setFullScreen(false);
      setIsMoreMenuOpen(false);
      navigate(`/artist/${currentSong.artists.primary[0].id}`, { 
          state: { artist: currentSong.artists.primary[0] } 
      });
  };

  const handleViewAlbum = () => {
      if (!currentSong) return;
      setFullScreen(false);
      setIsMoreMenuOpen(false);
      navigate(`/album/${currentSong.album.id}`);
  };

  const handleShare = () => {
      // Simulate share
      const url = window.location.href;
      navigator.clipboard.writeText(url);
      alert("Link copied to clipboard!");
      setIsMoreMenuOpen(false);
  };

  const handleAddToPlaylist = (playlistId: string) => {
      if (!currentSong) return;
      addSongToPlaylist(playlistId, currentSong);
      setShowPlaylistSelector(false);
      setIsMoreMenuOpen(false);
  };

  if (!currentSong) return null;

  const imageUrl = getImageUrl(currentSong.image);
  const primaryArtistName = currentSong.artists?.primary?.[0]?.name || currentSong.artists?.all?.[0]?.name || "Unknown Artist";

  // Smooth configuration for image morphing
  const transitionConfig = {
    type: "tween",
    ease: "circOut",
    duration: 0.3
  };

  return (
    <>
        <audio 
            ref={audioRef}
            preload="auto"
            onTimeUpdate={handleTimeUpdate}
            onEnded={nextSong}
            onWaiting={() => setIsBuffering(true)}
            onPlaying={() => setIsBuffering(false)}
            onCanPlay={() => setIsBuffering(false)}
            onPause={() => {
                if (isPlaying && !isBuffering && audioRef.current?.paused && audioRef.current?.readyState > 2) setIsPlaying(false);
            }}
            onPlay={() => !isPlaying && setIsPlaying(true)}
            onError={() => { setIsBuffering(false); setIsPlaying(false); }}
        />

        <AnimatePresence mode="wait"> 
        {isFullScreen ? (
            /* --- FULL PLAYER --- */
            <motion.div 
                key="full-player"
                initial={{ y: "100%" }}
                animate={{ y: 0 }}
                exit={{ y: "100%" }}
                transition={{ 
                   type: "tween", 
                   ease: "circOut",
                   duration: 0.3
                }}
                className="fixed inset-0 z-[200] flex flex-col bg-[#121212] overflow-hidden font-sans touch-none"
                onClick={(e) => e.stopPropagation()}
                onTouchStart={handleTouchStart}
                onTouchEnd={handleTouchEnd}
            >
                {/* Dynamic Background */}
                <div 
                    className="absolute inset-0 z-0 pointer-events-none transition-colors duration-700 ease-in-out"
                    style={{ background: `linear-gradient(to bottom, ${dominantColor}, #121212)` }}
                />

                <div className="relative z-10 flex flex-col h-full text-white px-6 pb-8 pt-safe-top md:px-12 md:pb-12">

                    {/* Header */}
                    <div className="flex items-center justify-between shrink-0 h-16 mt-2">
                        <button onClick={() => setFullScreen(false)} className="p-2 -ml-2 hover:bg-white/10 rounded-full active:scale-95 transition-transform">
                            <ChevronDown size={28} className="text-white" />
                        </button>
                        <div className="flex flex-col items-center opacity-80">
                            <span className="text-[10px] font-bold tracking-[0.2em] uppercase text-white/60">
                                {isOfflineMode ? "Offline Mode" : "Now Playing"}
                            </span>
                        </div>
                        <button 
                            onClick={() => { setShowPlaylistSelector(false); setIsMoreMenuOpen(true); }}
                            className="p-2 -mr-2 hover:bg-white/10 rounded-full active:scale-95 transition-transform"
                        >
                            <MoreHorizontal size={24} className="text-white" />
                        </button>
                    </div>

                    {/* Album Art (Shared ID - Morphs position) */}
                    <div className="flex-1 flex items-center justify-center py-4 min-h-0">
                         <div className="relative w-full max-w-[340px] aspect-square">
                            <motion.img 
                                layoutId="player-image"
                                src={imageUrl} 
                                alt={currentSong.name} 
                                className="w-full h-full object-cover rounded-xl shadow-[0_8px_40px_rgba(0,0,0,0.5)]"
                                transition={transitionConfig}
                            />
                         </div>
                    </div>

                    {/* Track Info */}
                    <div className="flex flex-col gap-6 shrink-0 w-full max-w-lg mx-auto mb-6 md:mb-10">
                        <div className="flex items-center justify-between">
                            <div className="flex flex-col overflow-hidden mr-6 flex-1">
                                <motion.h1 
                                    initial={{ opacity: 0, x: -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ delay: 0.2 }}
                                    className="text-2xl md:text-3xl font-bold text-white whitespace-nowrap overflow-hidden text-ellipsis"
                                >
                                    {currentSong.name}
                                </motion.h1>
                                <motion.div 
                                    initial={{ opacity: 0, x: -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ delay: 0.3 }}
                                    className="flex items-center gap-2 mt-1"
                                >
                                    <p className="text-white/60 text-lg md:text-xl truncate font-medium">
                                        {primaryArtistName}
                                    </p>
                                    {isDownloaded && <CheckCircle2 size={16} className="text-[#1DB954]" />}
                                </motion.div>
                            </div>
                            <button onClick={() => toggleLike(currentSong)} className="transition-transform active:scale-75 shrink-0">
                                {isLiked ? <CheckCircle2 size={32} className="text-[#1DB954] fill-[#1DB954] text-black" /> : <PlusCircle size={32} className="text-white/60" />}
                            </button>
                        </div>

                        {/* Controls */}
                        <motion.div 
                            initial={{ opacity: 0, y: 20 }} 
                            animate={{ opacity: 1, y: 0 }} 
                            transition={{ delay: 0.2, duration: 0.3 }}
                            className="flex flex-col gap-2 pt-2"
                        >
                            {/* Scrubber */}
                            <div className="relative h-1 w-full bg-white/20 rounded-full group hover:h-1.5 transition-all">
                                 <div className="absolute left-0 top-0 bottom-0 bg-white rounded-full" style={{ width: `${(progress / (duration || 1)) * 100}%` }}>
                                    <div className="absolute right-0 top-1/2 -translate-y-1/2 w-3 h-3 bg-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity"></div>
                                 </div>
                                 <input 
                                    type="range" min="0" max={duration || 100} value={progress}
                                    onChange={handleSeek} onTouchStart={handleSeekStart} onTouchEnd={handleSeekEnd}
                                    onMouseDown={handleSeekStart} onMouseUp={handleSeekEnd}
                                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                                />
                            </div>
                            <div className="flex justify-between text-[11px] text-white/40 font-bold font-mono">
                                <span>{formatTime(progress)}</span>
                                <span>{formatTime(duration)}</span>
                            </div>

                            {/* Buttons */}
                            <div className="flex items-center justify-between -mx-2 mt-4">
                                <button className={`p-2 ${isShuffling ? 'text-[#1DB954]' : 'text-white/40'}`}><Shuffle size={20} /></button>

                                <div className="flex items-center gap-6 md:gap-10">
                                    <button onClick={prevSong} className="text-white hover:text-white/70 active:scale-90 transition-transform"><SkipBack size={32} fill="currentColor" /></button>
                                    <button 
                                        onClick={togglePlay}
                                        disabled={isBuffering}
                                        className="bg-white text-black rounded-full w-16 h-16 flex items-center justify-center hover:scale-105 active:scale-90 transition-all shadow-md"
                                    >
                                        {isBuffering ? <Loader2 size={32} className="animate-spin" /> : isPlaying ? <Pause size={32} fill="currentColor" /> : <Play size={32} fill="currentColor" className="ml-1" />}
                                    </button>
                                    <button onClick={nextSong} className="text-white hover:text-white/70 active:scale-90 transition-transform"><SkipForward size={32} fill="currentColor" /></button>
                                </div>

                                <button className="p-2 text-white/40"><Repeat size={20} /></button>
                            </div>
                        </motion.div>
                    </div>

                    {/* Bottom Actions */}
                    <motion.div 
                        initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 0.3 }}
                        className="flex items-center justify-between px-2"
                    >
                         <button 
                            onClick={() => setDownloadSong(currentSong)} 
                            className={`${isDownloaded ? 'text-[#1DB954]' : 'text-white/50 hover:text-white'}`}
                        >
                            <Download size={22} fill={isDownloaded ? "#1DB954" : "none"} />
                        </button>
                        <div className="flex items-center gap-6">
                            <button className="text-white/50 hover:text-white"><Mic2 size={22} /></button>
                            <button className="text-white/50 hover:text-white"><ListMusic size={24} /></button>
                        </div>
                    </motion.div>
                </div>

                {/* --- MORE OPTIONS MENU OVERLAY --- */}
                <AnimatePresence>
                    {isMoreMenuOpen && (
                        <motion.div 
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            className="absolute inset-0 z-[250] bg-black/60 backdrop-blur-sm flex flex-col justify-end"
                            onClick={() => setIsMoreMenuOpen(false)}
                        >
                            <motion.div 
                                initial={{ y: "100%" }}
                                animate={{ y: 0 }}
                                exit={{ y: "100%" }}
                                transition={{ type: "tween", ease: "circOut", duration: 0.3 }}
                                className="bg-[#1E1E1E] rounded-t-2xl overflow-hidden max-h-[70vh] flex flex-col"
                                onClick={(e) => e.stopPropagation()}
                            >
                                {/* Dragger */}
                                <div className="w-full flex justify-center pt-3 pb-1">
                                    <div className="w-10 h-1 bg-white/20 rounded-full"></div>
                                </div>

                                {!showPlaylistSelector ? (
                                    /* MAIN MENU */
                                    <div className="p-4 flex flex-col gap-2">
                                        <div className="flex items-center gap-3 p-2 mb-2 border-b border-white/10 pb-4">
                                            <img src={imageUrl} className="w-12 h-12 rounded-md object-cover" alt="" />
                                            <div className="flex flex-col">
                                                <span className="font-bold text-white text-sm">{currentSong.name}</span>
                                                <span className="text-xs text-[#B3B3B3]">{primaryArtistName}</span>
                                            </div>
                                        </div>

                                        <button 
                                            onClick={() => setShowPlaylistSelector(true)}
                                            className="flex items-center gap-4 p-3 hover:bg-white/5 rounded-lg text-white font-medium transition-colors"
                                        >
                                            <ListPlus size={22} className="text-[#B3B3B3]" /> Add to Playlist
                                        </button>
                                        <button 
                                            onClick={handleViewArtist}
                                            className="flex items-center gap-4 p-3 hover:bg-white/5 rounded-lg text-white font-medium transition-colors"
                                        >
                                            <User size={22} className="text-[#B3B3B3]" /> View Artist
                                        </button>
                                        <button 
                                            onClick={handleViewAlbum}
                                            className="flex items-center gap-4 p-3 hover:bg-white/5 rounded-lg text-white font-medium transition-colors"
                                        >
                                            <Disc size={22} className="text-[#B3B3B3]" /> View Album
                                        </button>
                                        <button 
                                            onClick={handleShare}
                                            className="flex items-center gap-4 p-3 hover:bg-white/5 rounded-lg text-white font-medium transition-colors"
                                        >
                                            <Share2 size={22} className="text-[#B3B3B3]" /> Share
                                        </button>

                                        <div className="p-2 mt-2">
                                            <button onClick={() => setIsMoreMenuOpen(false)} className="w-full py-3 rounded-full font-bold text-white/50 hover:text-white">
                                                Cancel
                                            </button>
                                        </div>
                                    </div>
                                ) : (
                                    /* PLAYLIST SELECTOR */
                                    <div className="flex flex-col h-full">
                                        <div className="flex items-center gap-2 p-4 border-b border-white/10">
                                            <button onClick={() => setShowPlaylistSelector(false)} className="p-1">
                                                <ChevronLeft size={24} />
                                            </button>
                                            <span className="font-bold text-white">Add to playlist</span>
                                        </div>

                                        <div className="overflow-y-auto max-h-[400px] p-2">
                                            <button 
                                                className="flex items-center gap-3 p-3 w-full hover:bg-white/5 rounded-lg mb-2"
                                                onClick={() => { /* Open Create Modal logic if needed, simplify for now */ }}
                                            >
                                                <div className="w-12 h-12 bg-[#2A2A2A] flex items-center justify-center rounded-md">
                                                    <PlusCircle size={24} className="text-white" />
                                                </div>
                                                <span className="font-bold text-white">New Playlist</span>
                                            </button>

                                            {userPlaylists.map(pl => {
                                                const isAdded = pl.songs.some(s => s.id === currentSong.id);
                                                return (
                                                    <button 
                                                        key={pl.id}
                                                        onClick={() => !isAdded && handleAddToPlaylist(pl.id)}
                                                        className="flex items-center justify-between p-3 w-full hover:bg-white/5 rounded-lg"
                                                        disabled={isAdded}
                                                    >
                                                        <div className="flex items-center gap-3">
                                                            <div className="w-12 h-12 bg-[#333] rounded-md overflow-hidden">
                                                                {pl.image?.[0] ? <img src={getImageUrl(pl.image)} className="w-full h-full object-cover" alt=""/> : <ListMusic className="m-auto mt-3 text-white/50" />}
                                                            </div>
                                                            <div className="flex flex-col text-left">
                                                                <span className={`font-bold text-sm ${isAdded ? 'text-[#1DB954]' : 'text-white'}`}>{pl.title}</span>
                                                                <span className="text-xs text-[#777]">{pl.songs.length} songs</span>
                                                            </div>
                                                        </div>
                                                        {isAdded && <Check size={20} className="text-[#1DB954]" />}
                                                    </button>
                                                )
                                            })}
                                        </div>
                                    </div>
                                )}
                            </motion.div>
                        </motion.div>
                    )}
                </AnimatePresence>

            </motion.div>
        ) : (
            /* --- MINI PLAYER (REDESIGNED) --- */
            <motion.div 
                key="mini-player"
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: 20 }}
                transition={{ type: "tween", ease: "easeOut", duration: 0.2 }}
                onClick={() => setFullScreen(true)}
                style={{ backgroundColor: dominantColor }}
                className="fixed bottom-[68px] md:bottom-4 left-2 right-2 md:left-1/2 md:-translate-x-1/2 md:w-[450px] h-[60px] rounded-xl flex items-center px-4 shadow-xl z-[150] cursor-pointer overflow-hidden"
            >
                {/* Darken overlay for better text contrast if color is too bright */}
                <div className="absolute inset-0 bg-black/10 pointer-events-none" />

                <div className="relative z-10 flex items-center w-full gap-3">
                    {/* Image (Shared ID - Morphs position) */}
                    <div className="relative h-10 w-10 shrink-0">
                        <motion.img 
                            layoutId="player-image"
                            src={imageUrl} 
                            alt="cover" 
                            className="h-full w-full object-cover rounded shadow-md" 
                            transition={transitionConfig}
                        />
                    </div>

                    {/* Text */}
                    <div className="flex-1 min-w-0 flex flex-col justify-center">
                        <div className="flex items-center gap-1.5">
                            <span className="text-white font-bold text-sm truncate">
                                {currentSong.name}
                            </span>
                            {isDownloaded && isOfflineMode && <CheckCircle2 size={12} className="text-white" />}
                        </div>
                        <span className="text-white/80 text-xs truncate">
                            {primaryArtistName}
                        </span>
                    </div>

                    {/* Controls */}
                    <div className="flex items-center gap-4">
                         <button onClick={(e) => { e.stopPropagation(); toggleLike(currentSong); }}>
                            <Heart size={24} fill={isLiked ? "white" : "transparent"} className="text-white drop-shadow-sm" />
                         </button>
                         <button onClick={(e) => { e.stopPropagation(); togglePlay(); }}>
                            {isBuffering ? (
                                <Loader2 size={28} className="animate-spin text-white/80" />
                            ) : isPlaying ? (
                                <Pause size={28} fill="white" className="text-white drop-shadow-sm" />
                            ) : (
                                <Play size={28} fill="white" className="text-white drop-shadow-sm" />
                            )}
                         </button>
                    </div>
                </div>

                 {/* Subtle Progress Bar Line at Bottom */}
                <div className="absolute bottom-0 left-0 right-0 h-[3px] bg-black/10 pointer-events-none">
                     <div className="h-full bg-white/40 rounded-r-full transition-all duration-300 ease-linear" style={{ width: `${(progress / (duration || 1)) * 100}%` }}></div>
                </div>
            </motion.div>
        )}
        </AnimatePresence>

        {downloadSong && (
            <DownloadQualityModal song={downloadSong} onClose={() => setDownloadSong(null)} />
        )}
    </>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { Play, Pause, SkipBack, SkipForward, ChevronDown, MoreHorizontal, Download, ListMusic, Heart, Loader2, Shuffle, Repeat, Mic2, PlusCircle, CheckCircle2, Disc, User, Share2, ListPlus, X, Check, ChevronLeft } from 'lucide-react';
import { usePlayerStore } from '../store/playerStore';
import { getImageUrl, getAudioUrl, getOfflineAudioUrl } from '../services/api';
import { AnimatePresence, motion } from 'framer-motion';
import { DownloadQualityModal } from './DownloadQualityModal';
import { Song } from '../types';
import { useNavigate } from 'react-router-dom';

export const Player: React.FC = () => {
  const { 
    currentSong, 
    isPlaying, 
    isBuffering,
    isFullScreen,
    setFullScreen,
    togglePlay, 
    setIsPlaying, 
    setIsBuffering,
    nextSong, 
    prevSong,
    likedSongs,
    toggleLike,
    isShuffling,
    streamingQuality,
    isOfflineMode,
    downloadedSongIds,
    userPlaylists,
    addSongToPlaylist
  } = usePlayerStore();

  const navigate = useNavigate();
  const audioRef = useRef<HTMLAudioElement>(null);
  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);
  const [dominantColor, setDominantColor] = useState<string>('#222222');
  const [isDragging, setIsDragging] = useState(false);

  // Modals state
  const [downloadSong, setDownloadSong] = useState<Song | null>(null);
  const [isMoreMenuOpen, setIsMoreMenuOpen] = useState(false);
  const [showPlaylistSelector, setShowPlaylistSelector] = useState(false);

  const [touchStart, setTouchStart] = useState<{x: number, y: number} | null>(null);

  const isLiked = currentSong ? likedSongs.some(s => s.id === currentSong.id) : false;
  const isDownloaded = currentSong ? downloadedSongIds.includes(currentSong.id) : false;

  useEffect(() => {
    if (!currentSong) return;

    const imgUrl = getImageUrl(currentSong.image);
    const img = new Image();
    img.crossOrigin = "Anonymous";
    img.src = imgUrl;

    img.onload = () => {
      try {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) return;
        canvas.width = 1;
        canvas.height = 1;
        ctx.drawImage(img, 0, 0, 1, 1);
        const [r, g, b] = ctx.getImageData(0, 0, 1, 1).data;
        setDominantColor(`rgb(${r},${g},${b})`);
      } catch (e) {
        setDominantColor('#222222'); 
      }
    };
    img.onerror = () => setDominantColor('#222222');
  }, [currentSong?.id]);

  useEffect(() => {
    if (!currentSong || !audioRef.current) return;

    const setAudioSource = async () => {
        let url = '';

        // OFFLINE LOGIC
        if (isOfflineMode || downloadedSongIds.includes(currentSong.id)) {
            const blobUrl = await getOfflineAudioUrl(currentSong.id);
            if (blobUrl) {
                url = blobUrl;
                console.log("Playing from Offline Storage");
            } else if (isOfflineMode) {
                console.warn("Song not available offline");
                setIsPlaying(false);
                return;
            }
        }

        // Fallback to Network
        if (!url && !isOfflineMode) {
             url = getAudioUrl(currentSong.downloadUrl, streamingQuality);
        }

        if (url && audioRef.current && audioRef.current.src !== url) {
            const wasPlaying = isPlaying;
            audioRef.current.src = url;
            audioRef.current.load();
            if (wasPlaying) {
                 const playPromise = audioRef.current.play();
                 if (playPromise !== undefined) {
                     playPromise.catch(error => {
                         console.warn("Autoplay prevented:", error);
                         setIsPlaying(false);
                     });
                 }
            }
        }
    };

    setAudioSource();

    return () => {
        if (audioRef.current?.src.startsWith('blob:')) {
            URL.revokeObjectURL(audioRef.current.src);
        }
    };
  }, [currentSong?.id, streamingQuality, isOfflineMode, downloadedSongIds]);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;
    if (isPlaying && audio.paused) audio.play().catch(e => console.warn("Play interrupted", e));
    else if (!isPlaying && !audio.paused) audio.pause();
  }, [isPlaying]);

  const handleTimeUpdate = () => {
    if (audioRef.current && !isDragging) {
      setProgress(audioRef.current.currentTime);
      setDuration(audioRef.current.duration || 0);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);
    setProgress(time);
    if (audioRef.current) audioRef.current.currentTime = time;
  };

  const handleSeekStart = () => setIsDragging(true);
  const handleSeekEnd = () => {
      setIsDragging(false);
       if (audioRef.current) audioRef.current.currentTime = progress;
  };

  const formatTime = (seconds: number) => {
    if (!seconds || isNaN(seconds)) return "-:--";
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    setTouchStart({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY });
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (!touchStart) return;
    const touchEndX = e.changedTouches[0].clientX;
    const touchEndY = e.changedTouches[0].clientY;
    const diffX = touchStart.x - touchEndX;
    const diffY = touchStart.y - touchEndY;

    if (Math.abs(diffX) > 50 && Math.abs(diffX) > Math.abs(diffY)) {
      if (diffX > 0) nextSong();
      else prevSong();
    }

    // Swipe Down to close (only if menu is not open)
    if (diffY < -80 && Math.abs(diffY) > Math.abs(diffX) && !isMoreMenuOpen) {
        setFullScreen(false);
    }
    setTouchStart(null);
  };

  // --- ACTIONS ---
  const handleViewArtist = () => {
      if (!currentSong) return;
      setFullScreen(false);
      setIsMoreMenuOpen(false);
      navigate(`/artist/${currentSong.artists.primary[0].id}`, { 
          state: { artist: currentSong.artists.primary[0] } 
      });
  };

  const handleViewAlbum = () => {
      if (!currentSong) return;
      setFullScreen(false);
      setIsMoreMenuOpen(false);
      navigate(`/album/${currentSong.album.id}`);
  };

  const handleShare = () => {
      const url = window.location.href;
      navigator.clipboard.writeText(url);
      alert("Link copied to clipboard!");
      setIsMoreMenuOpen(false);
  };

  const handleAddToPlaylist = (playlistId: string) => {
      if (!currentSong) return;
      addSongToPlaylist(playlistId, currentSong);
      setShowPlaylistSelector(false);
      setIsMoreMenuOpen(false);
  };

  if (!currentSong) return null;

  const imageUrl = getImageUrl(currentSong.image);
  const primaryArtistName = currentSong.artists?.primary?.[0]?.name || currentSong.artists?.all?.[0]?.name || "Unknown Artist";

  const transitionConfig = {
    type: "tween",
    ease: "circOut",
    duration: 0.3
  };

  return (
    <>
        <audio 
            ref={audioRef}
            preload="auto"
            onTimeUpdate={handleTimeUpdate}
            onEnded={nextSong}
            onWaiting={() => setIsBuffering(true)}
            onPlaying={() => setIsBuffering(false)}
            onCanPlay={() => setIsBuffering(false)}
            onPause={() => {
                if (isPlaying && !isBuffering && audioRef.current?.paused && audioRef.current?.readyState > 2) setIsPlaying(false);
            }}
            onPlay={() => !isPlaying && setIsPlaying(true)}
            onError={() => { setIsBuffering(false); setIsPlaying(false); }}
        />

        <AnimatePresence mode="wait"> 
        {isFullScreen ? (
            /* --- FULL PLAYER --- */
            <motion.div 
                key="full-player"
                initial={{ y: "100%" }}
                animate={{ y: 0 }}
                exit={{ y: "100%" }}
                transition={{ 
                   type: "tween", 
                   ease: "circOut",
                   duration: 0.3
                }}
                className="fixed inset-0 z-[200] flex flex-col bg-[#121212] overflow-hidden font-sans touch-none"
                onClick={(e) => e.stopPropagation()}
                onTouchStart={handleTouchStart}
                onTouchEnd={handleTouchEnd}
            >
                {/* Dynamic Background */}
                <div 
                    className="absolute inset-0 z-0 pointer-events-none transition-colors duration-700 ease-in-out"
                    style={{ background: `linear-gradient(to bottom, ${dominantColor}, #121212)` }}
                />

                <div className="relative z-10 flex flex-col h-full text-white px-6 pb-8 pt-safe-top md:px-12 md:pb-12">

                    {/* Header */}
                    <div className="flex items-center justify-between shrink-0 h-16 mt-2">
                        <button onClick={() => setFullScreen(false)} className="p-2 -ml-2 hover:bg-white/10 rounded-full active:scale-95 transition-transform">
                            <ChevronDown size={28} className="text-white" />
                        </button>
                        <div className="flex flex-col items-center opacity-80">
                            <span className="text-[10px] font-bold tracking-[0.2em] uppercase text-white/60">
                                {isOfflineMode ? "Offline Mode" : "Now Playing"}
                            </span>
                        </div>
                        <button 
                            onClick={() => { setShowPlaylistSelector(false); setIsMoreMenuOpen(true); }}
                            className="p-2 -mr-2 hover:bg-white/10 rounded-full active:scale-95 transition-transform"
                        >
                            <MoreHorizontal size={24} className="text-white" />
                        </button>
                    </div>

                    {/* Album Art */}
                    <div className="flex-1 flex items-center justify-center py-4 min-h-0">
                         <div className="relative w-full max-w-[340px] aspect-square">
                            <motion.img 
                                layoutId="player-image"
                                src={imageUrl} 
                                alt={currentSong.name} 
                                className="w-full h-full object-cover rounded-xl shadow-[0_8px_40px_rgba(0,0,0,0.5)]"
                                transition={transitionConfig}
                            />
                         </div>
                    </div>

                    {/* Track Info */}
                    <div className="flex flex-col gap-6 shrink-0 w-full max-w-lg mx-auto mb-6 md:mb-10">
                        <div className="flex items-center justify-between">
                            <div className="flex flex-col overflow-hidden mr-6 flex-1">
                                <motion.h1 
                                    initial={{ opacity: 0, x: -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ delay: 0.2 }}
                                    className="text-2xl md:text-3xl font-bold text-white whitespace-nowrap overflow-hidden text-ellipsis"
                                >
                                    {currentSong.name}
                                </motion.h1>
                                <motion.div 
                                    initial={{ opacity: 0, x: -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ delay: 0.3 }}
                                    className="flex items-center gap-2 mt-1"
                                >
                                    <p className="text-white/60 text-lg md:text-xl truncate font-medium">
                                        {primaryArtistName}
                                    </p>
                                    {isDownloaded && <CheckCircle2 size={16} className="text-[#1DB954]" />}
                                </motion.div>
                            </div>
                            <button onClick={() => toggleLike(currentSong)} className="transition-transform active:scale-75 shrink-0">
                                {isLiked ? <CheckCircle2 size={32} className="text-[#1DB954] fill-[#1DB954] text-black" /> : <PlusCircle size={32} className="text-white/60" />}
                            </button>
                        </div>

                        {/* Controls */}
                        <motion.div 
                            initial={{ opacity: 0, y: 20 }} 
                            animate={{ opacity: 1, y: 0 }} 
                            transition={{ delay: 0.2, duration: 0.3 }}
                            className="flex flex-col gap-2 pt-2"
                        >
                            {/* Scrubber */}
                            <div className="relative h-1 w-full bg-white/20 rounded-full group hover:h-1.5 transition-all">
                                 <div className="absolute left-0 top-0 bottom-0 bg-white rounded-full" style={{ width: `${(progress / (duration || 1)) * 100}%` }}>
                                    <div className="absolute right-0 top-1/2 -translate-y-1/2 w-3 h-3 bg-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity"></div>
                                 </div>
                                 <input 
                                    type="range" min="0" max={duration || 100} value={progress}
                                    onChange={handleSeek} onTouchStart={handleSeekStart} onTouchEnd={handleSeekEnd}
                                    onMouseDown={handleSeekStart} onMouseUp={handleSeekEnd}
                                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                                />
                            </div>
                            <div className="flex justify-between text-[11px] text-white/40 font-bold font-mono">
                                <span>{formatTime(progress)}</span>
                                <span>{formatTime(duration)}</span>
                            </div>

                            {/* Buttons */}
                            <div className="flex items-center justify-between -mx-2 mt-4">
                                <button className={`p-2 ${isShuffling ? 'text-[#1DB954]' : 'text-white/40'}`}><Shuffle size={20} /></button>

                                <div className="flex items-center gap-6 md:gap-10">
                                    <button onClick={prevSong} className="text-white hover:text-white/70 active:scale-90 transition-transform"><SkipBack size={32} fill="currentColor" /></button>
                                    <button 
                                        onClick={togglePlay}
                                        disabled={isBuffering}
                                        className="bg-white text-black rounded-full w-16 h-16 flex items-center justify-center hover:scale-105 active:scale-90 transition-all shadow-md"
                                    >
                                        {isBuffering ? <Loader2 size={32} className="animate-spin" /> : isPlaying ? <Pause size={32} fill="currentColor" /> : <Play size={32} fill="currentColor" className="ml-1" />}
                                    </button>
                                    <button onClick={nextSong} className="text-white hover:text-white/70 active:scale-90 transition-transform"><SkipForward size={32} fill="currentColor" /></button>
                                </div>

                                <button className="p-2 text-white/40"><Repeat size={20} /></button>
                            </div>
                        </motion.div>
                    </div>

                    {/* Bottom Actions */}
                    <motion.div 
                        initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 0.3 }}
                        className="flex items-center justify-between px-2"
                    >
                         <button 
                            onClick={() => setDownloadSong(currentSong)} 
                            className={`${isDownloaded ? 'text-[#1DB954]' : 'text-white/50 hover:text-white'}`}
                        >
                            <Download size={22} fill={isDownloaded ? "#1DB954" : "none"} />
                        </button>
                        <div className="flex items-center gap-6">
                            <button className="text-white/50 hover:text-white"><Mic2 size={22} /></button>
                            <button className="text-white/50 hover:text-white"><ListMusic size={24} /></button>
                        </div>
                    </motion.div>
                </div>

                {/* --- MORE OPTIONS MENU OVERLAY --- */}
                <AnimatePresence>
                    {isMoreMenuOpen && (
                        <motion.div 
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            className="absolute inset-0 z-[250] bg-black/60 backdrop-blur-sm flex flex-col justify-end"
                            onClick={() => setIsMoreMenuOpen(false)}
                        >
                            <motion.div 
                                initial={{ y: "100%" }}
                                animate={{ y: 0 }}
                                exit={{ y: "100%" }}
                                transition={{ type: "tween", ease: "circOut", duration: 0.3 }}
                                className="bg-[#1E1E1E] rounded-t-2xl overflow-hidden max-h-[70vh] flex flex-col"
                                onClick={(e) => e.stopPropagation()}
                            >
                                {/* Dragger */}
                                <div className="w-full flex justify-center pt-3 pb-1">
                                    <div className="w-10 h-1 bg-white/20 rounded-full"></div>
                                </div>

                                {!showPlaylistSelector ? (
                                    /* MAIN MENU */
                                    <div className="p-4 flex flex-col gap-2">
                                        <div className="flex items-center gap-3 p-2 mb-2 border-b border-white/10 pb-4">
                                            <img src={imageUrl} className="w-12 h-12 rounded-md object-cover" alt="" />
                                            <div className="flex flex-col">
                                                <span className="font-bold text-white text-sm">{currentSong.name}</span>
                                                <span className="text-xs text-[#B3B3B3]">{primaryArtistName}</span>
                                            </div>
                                        </div>

                                        <button 
                                            onClick={() => setShowPlaylistSelector(true)}
                                            className="flex items-center gap-4 p-3 hover:bg-white/5 rounded-lg text-white font-medium transition-colors"
                                        >
                                            <ListPlus size={22} className="text-[#B3B3B3]" /> Add to Playlist
                                        </button>
                                        <button 
                                            onClick={handleViewArtist}
                                            className="flex items-center gap-4 p-3 hover:bg-white/5 rounded-lg text-white font-medium transition-colors"
                                        >
                                            <User size={22} className="text-[#B3B3B3]" /> View Artist
                                        </button>
                                        <button 
                                            onClick={handleViewAlbum}
                                            className="flex items-center gap-4 p-3 hover:bg-white/5 rounded-lg text-white font-medium transition-colors"
                                        >
                                            <Disc size={22} className="text-[#B3B3B3]" /> View Album
                                        </button>
                                        <button 
                                            onClick={handleShare}
                                            className="flex items-center gap-4 p-3 hover:bg-white/5 rounded-lg text-white font-medium transition-colors"
                                        >
                                            <Share2 size={22} className="text-[#B3B3B3]" /> Share
                                        </button>

                                        <div className="p-2 mt-2">
                                            <button onClick={() => setIsMoreMenuOpen(false)} className="w-full py-3 rounded-full font-bold text-white/50 hover:text-white">
                                                Cancel
                                            </button>
                                        </div>
                                    </div>
                                ) : (
                                    /* PLAYLIST SELECTOR */
                                    <div className="flex flex-col h-full">
