export const Search: React.FC = () => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<{ songs: Song[], albums: Album[], artists: Artist[] }>({ songs: [], albums: [], artists: [] });
  const [isLoading, setIsLoading] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [isFocused, setIsFocused] = useState(false);

  const { playSong, likedSongs, toggleLike } = usePlayerStore();
  const navigate = useNavigate();

  // AbortController to handle race conditions
  const abortControllerRef = useRef<AbortController | null>(null);

  useEffect(() => {
    // Cancel any ongoing fetch if query changes
    if (abortControllerRef.current) {
        abortControllerRef.current.abort();
    }

    if (!query.trim()) {
        setResults({ songs: [], albums: [], artists: [] });
        setSuggestions([]);
        setIsLoading(false);
        return;
    }

    setIsLoading(true);

    const timer = setTimeout(async () => {
        abortControllerRef.current = new AbortController();
        try {
           const [songs, albums, artists] = await Promise.all([
              api.searchSongs(query),
              api.searchAlbums(query),
              api.searchArtists(query)
           ]);

           // Only update if not aborted
           if (!abortControllerRef.current?.signal.aborted) {
               setResults({ songs, albums, artists });

               // Generate Related Keywords from results
               const rawTitles = songs.map(s => s.name.toLowerCase());
               const artistNames = artists.slice(0, 2).map(a => a.name.toLowerCase());

               const derivedSuggestions = Array.from(new Set([
                   query.toLowerCase(), 
                   ...rawTitles.filter(t => t.includes(query.toLowerCase()) && t !== query.toLowerCase()),
                   ...artistNames,
                   ...rawTitles
               ])).slice(0, 4); 

               setSuggestions(derivedSuggestions);
           }
        } catch (e: any) {
            if (e.name !== 'AbortError') {
                console.error(e);
            }
        } finally {
            if (!abortControllerRef.current?.signal.aborted) {
                setIsLoading(false);
            }
        }
    }, 300);

    return () => clearTimeout(timer);
  }, [query]);

  const clearSearch = () => {
    setQuery('');
    setResults({ songs: [], albums: [], artists: [] });
    setSuggestions([]);
    setIsLoading(false);
  };

  const ResultSkeleton = () => (
      <div className="flex items-center gap-3 px-4 py-2.5 animate-pulse">
          <div className="w-12 h-12 bg-white/10 rounded-md shrink-0"></div>
          <div className="flex-1 space-y-2 py-1">
              <div className="h-4 bg-white/10 rounded w-1/3"></div>
              <div className="h-3 bg-white/5 rounded w-1/4"></div>
          </div>
      </div>
  );

  return (
    <div className="flex flex-col min-h-full pb-32 bg-black">

      {/* Search Header */}
      <div className="sticky top-0 bg-[#121212] z-30 px-4 py-3 border-b border-white/5 transition-colors duration-300">
         <div className="flex items-center gap-3">
             <button onClick={() => navigate(-1)} className="text-white hover:bg-white/10 p-2 rounded-full transition-colors active:scale-95 md:hidden">
                <ArrowLeft size={24} />
             </button>

             {/* Premium Search Bar */}
             <div className={`flex-1 relative group transition-all duration-300 ease-out ${isFocused ? 'scale-[1.01]' : 'scale-100'}`}>
                {/* Search Icon */}
                <div className={`absolute inset-y-0 left-3.5 flex items-center pointer-events-none transition-colors duration-300 ${isFocused ? 'text-white' : 'text-[#777]'}`}>
                     <SearchIcon size={20} />
                </div>

                {/* Input Field */}
                <input 
                  type="text"
                  className="w-full bg-[#242424] hover:bg-[#2a2a2a] focus:bg-[#1f1f1f] text-white rounded-full py-3 pl-11 pr-11 outline-none border border-transparent focus:border-white/10 focus:shadow-[0_0_20px_rgba(255,255,255,0.03)] placeholder-[#777] font-medium text-[16px] transition-all duration-300 ease-out"
                  placeholder="What do you want to listen to?"
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                  onFocus={() => setIsFocused(true)}
                  onBlur={() => setIsFocused(false)}
                  autoFocus={false}
                />

                {/* Clear / Loading Action */}
                {(query || isLoading) && (
                    <div className="absolute right-3.5 top-1/2 -translate-y-1/2 flex items-center">
                         {isLoading ? (
                             <Loader2 size={18} className="text-[#1DB954] animate-spin" />
                         ) : (
                             <button onClick={clearSearch} className="text-[#777] hover:text-white p-1 rounded-full hover:bg-white/10 transition-colors">
                                 <X size={18} />
                             </button>
                         )}
                    </div>
                )}
             </div>
         </div>
      </div>

      {/* Browse All (Initial State) */}
      {!query && (
         <div className="p-4">
             <h2 className="text-white font-bold text-lg mb-4">Browse all</h2>
             <motion.div 
                variants={containerVariants}
                initial="hidden"
                animate="visible"
                className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-4"
             >
                 {BROWSE_CATEGORIES.map((cat, idx) => (
                     <motion.div 
                        key={idx} 
                        variants={itemVariants}
                        whileHover={{ scale: 1.02 }}
                        whileTap={{ scale: 0.98 }}
                        className={`${cat.color} aspect-[1.6/1] rounded-lg p-4 relative overflow-hidden cursor-pointer hover:opacity-90 transition-opacity`}
                        onClick={() => setQuery(cat.title)} 
                     >
                         <h3 className="text-white font-bold text-xl md:text-2xl break-words max-w-[80%] relative z-10 leading-tight">
                            {cat.title}
                         </h3>
                         <div className="absolute -bottom-2 -right-4 w-20 h-20 bg-black/20 rotate-[25deg] shadow-lg rounded-md flex items-center justify-center">
                         </div>
                     </motion.div>
                 ))}
             </motion.div>
         </div>
      )}

      {/* Loading State Skeleton */}
      {isLoading && !results.songs.length && (
          <div className="flex flex-col w-full pt-2">
              {[1,2,3,4,5].map(i => <ResultSkeleton key={i} />)}
          </div>
      )}

      {/* Results */}
      {query && (
        <div className="flex flex-col w-full pb-8">

            {/* 1. Related Keywords (Suggestions) */}
            {suggestions.length > 0 && (
                <div className="flex flex-col mb-2">
                    {suggestions.map((suggestion, idx) => (
                        <div 
                            key={idx}
                            onClick={() => setQuery(suggestion)}
                            className="flex items-center justify-between px-4 py-3.5 hover:bg-[#1A1A1A] active:bg-[#222] cursor-pointer transition-colors border-b border-white/5 last:border-0"
                        >
                            <div className="flex items-center gap-4">
                                <SearchIcon size={20} className="text-[#B3B3B3]" />
                                <span className="text-white text-[15px]">{suggestion}</span>
                            </div>
                            <ArrowUpLeft size={18} className="text-[#555] rotate-45" />
                        </div>
                    ))}
                </div>
            )}

            {/* 2. Songs List */}
            {results.songs.length > 0 && (
                <div className="animate-in fade-in slide-in-from-bottom-3 duration-300 delay-75">
                     {/* REMOVED SLICE TO SHOW ALL SONGS */}
                     {results.songs.map((song) => {
                         const isLiked = likedSongs.some(s => s.id === song.id);
                         const artistName = song.artists?.primary?.[0]?.name || "Unknown";

                         return (
                             <div 
                                key={song.id} 
                                className="flex items-center gap-3 px-4 py-2 hover:bg-[#1A1A1A] cursor-pointer group transition-colors" 
                                onClick={() => playSong(song, results.songs)}
                             >
                                 <div className="w-12 h-12 shrink-0 relative">
                                    <img src={getImageUrl(song.image)} className="w-full h-full rounded-[4px] object-cover" alt="" />
                                 </div>
                                 <div className="flex-1 min-w-0 flex flex-col justify-center gap-0.5">
                                     <div className={`font-medium truncate text-[16px] text-white ${isLiked ? 'text-[#1DB954]' : ''}`}>{song.name}</div>
                                     <div className="text-[#B3B3B3] text-sm truncate flex items-center gap-1">
                                        {song.name.toLowerCase().includes('explicit') && (
                                            <span className="bg-[#B3B3B3] text-black text-[9px] px-1 rounded-[2px] font-bold">E</span>
                                        )}
                                        <span>Song • {artistName}</span>
                                     </div>
                                 </div>

                                 <div className="flex items-center gap-4">
                                     <button 
                                        className="text-[#B3B3B3] hover:text-white transition-transform active:scale-90" 
                                        onClick={(e) => { e.stopPropagation(); toggleLike(song); }}
                                     >
                                        {isLiked ? (
                                            <CheckCircle2 size={22} className="text-[#1DB954] fill-[#1DB954] text-black" />
                                        ) : (
                                            <PlusCircle size={22} />
                                        )}
                                     </button>
                                     <button className="text-[#B3B3B3] hover:text-white" onClick={(e) => e.stopPropagation()}>
                                         <MoreVertical size={20} />
                                     </button>
                                 </div>
                             </div>
                         );
                     })}
                </div>
            )}

            {/* No Results */}
            {!isLoading && results.songs.length === 0 && suggestions.length === 0 && (
                <div className="flex flex-col items-center justify-center pt-20 text-[#777]">
                    <div className="w-20 h-20 bg-[#1A1A1A] rounded-full flex items-center justify-center mb-4">
                        <SearchIcon size={40} className="opacity-50"/>
                    </div>
                    <h3 className="text-white font-bold text-lg">No results found</h3>
                    <p className="text-sm mt-2">Try searching for a different song or artist.</p>
                </div>
            )}
        </div>
      )}
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { Play, Pause, SkipBack, SkipForward, ChevronDown, MoreHorizontal, Download, ListMusic, Heart, Loader2, Shuffle, Repeat, Mic2, PlusCircle, CheckCircle2, Disc, User, Share2, ListPlus, X, Check, ChevronLeft } from 'lucide-react';
import { usePlayerStore } from '../store/playerStore';
import { getImageUrl, getAudioUrl, getOfflineAudioUrl } from '../services/api';
import { AnimatePresence, motion } from 'framer-motion';
import { DownloadQualityModal } from './DownloadQualityModal';
import { Song } from '../types';
import { useNavigate } from 'react-router-dom';

export const Player: React.FC = () => {
  const { 
    currentSong, 
    isPlaying, 
    isBuffering,
    isFullScreen,
    setFullScreen,
    togglePlay, 
    setIsPlaying, 
    setIsBuffering,
    nextSong, 
    prevSong,
    likedSongs,
    toggleLike,
    isShuffling,
    streamingQuality,
    isOfflineMode,
    downloadedSongIds,
    userPlaylists,
    addSongToPlaylist
  } = usePlayerStore();

  const navigate = useNavigate();
  const audioRef = useRef<HTMLAudioElement>(null);
  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);
  const [dominantColor, setDominantColor] = useState<string>('#121212');
  const [isDragging, setIsDragging] = useState(false);

  // Modals state
  const [downloadSong, setDownloadSong] = useState<Song | null>(null);
  const [isMoreMenuOpen, setIsMoreMenuOpen] = useState(false);
  const [showPlaylistSelector, setShowPlaylistSelector] = useState(false);

  const [touchStart, setTouchStart] = useState<{x: number, y: number} | null>(null);

  const isLiked = currentSong ? likedSongs.some(s => s.id === currentSong.id) : false;
  const isDownloaded = currentSong ? downloadedSongIds.includes(currentSong.id) : false;

  // --- COLOR EXTRACTION LOGIC ---
  useEffect(() => {
    if (!currentSong) return;

    const imgUrl = getImageUrl(currentSong.image);
    const img = new Image();
    img.crossOrigin = "Anonymous";
    img.src = imgUrl;

    img.onload = () => {
      try {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        // Use a 20x20 sample to find the "vibe" color
        canvas.width = 20;
        canvas.height = 20;
        ctx.drawImage(img, 0, 0, 20, 20);
        const data = ctx.getImageData(0, 0, 20, 20).data;

        let rAcc = 0, gAcc = 0, bAcc = 0, count = 0;

        for(let i = 0; i < data.length; i+=4) {
            const r = data[i];
            const g = data[i+1];
            const b = data[i+2];

            // Calculate Saturation (approximation)
            const max = Math.max(r, g, b);
            const min = Math.min(r, g, b);
            const delta = max - min;
            const saturation = max === 0 ? 0 : delta / max;

            // Filter out whites, grays, and washed out colors to avoid "pink" result for red images
            if (saturation > 0.15) {
                rAcc += r;
                gAcc += g;
                bAcc += b;
                count++;
            }
        }

        let finalR, finalG, finalB;

        if (count > 0) {
             finalR = rAcc / count;
             finalG = gAcc / count;
             finalB = bAcc / count;
        } else {
             // Fallback for B&W or low sat images: Average everything
             let rTot = 0, gTot = 0, bTot = 0;
             for(let i = 0; i < data.length; i+=4) {
                 rTot += data[i]; gTot += data[i+1]; bTot += data[i+2];
             }
             const totalPixels = data.length / 4;
             finalR = rTot / totalPixels;
             finalG = gTot / totalPixels;
             finalB = bTot / totalPixels;
        }

        // Apply Darkening to ensure premium feel and good contrast
        const brightness = (finalR * 299 + finalG * 587 + finalB * 114) / 1000;

        // Target max brightness ~70 for background
        if (brightness > 70) {
            const factor = 70 / brightness;
            finalR *= factor;
            finalG *= factor;
            finalB *= factor;
        }

        setDominantColor(`rgb(${Math.round(finalR)},${Math.round(finalG)},${Math.round(finalB)})`);
      } catch (e) {
        setDominantColor('#121212'); 
      }
    };
    img.onerror = () => setDominantColor('#121212');
  }, [currentSong?.id]);

  useEffect(() => {
    if (!currentSong || !audioRef.current) return;

    const setAudioSource = async () => {
        let url = '';

        // OFFLINE LOGIC
        if (isOfflineMode || downloadedSongIds.includes(currentSong.id)) {
            const blobUrl = await getOfflineAudioUrl(currentSong.id);
            if (blobUrl) {
                url = blobUrl;
                console.log("Playing from Offline Storage");
            } else if (isOfflineMode) {
                console.warn("Song not available offline");
                setIsPlaying(false);
                return;
            }
        }

        // Fallback to Network
        if (!url && !isOfflineMode) {
             url = getAudioUrl(currentSong.downloadUrl, streamingQuality);
        }

        if (url && audioRef.current && audioRef.current.src !== url) {
            const wasPlaying = isPlaying;
            audioRef.current.src = url;
            audioRef.current.load();
            if (wasPlaying) {
                 const playPromise = audioRef.current.play();
                 if (playPromise !== undefined) {
                     playPromise.catch(error => {
                         console.warn("Autoplay prevented:", error);
                         setIsPlaying(false);
                     });
                 }
            }
        }
    };

    setAudioSource();

    return () => {
        if (audioRef.current?.src.startsWith('blob:')) {
            URL.revokeObjectURL(audioRef.current.src);
        }
    };
  }, [currentSong?.id, streamingQuality, isOfflineMode, downloadedSongIds]);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;
    if (isPlaying && audio.paused) audio.play().catch(e => console.warn("Play interrupted", e));
    else if (!isPlaying && !audio.paused) audio.pause();
  }, [isPlaying]);

  const handleTimeUpdate = () => {
    if (audioRef.current && !isDragging) {
      setProgress(audioRef.current.currentTime);
      setDuration(audioRef.current.duration || 0);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);
    setProgress(time);
    if (audioRef.current) audioRef.current.currentTime = time;
  };

  const handleSeekStart = () => setIsDragging(true);
  const handleSeekEnd = () => {
      setIsDragging(false);
       if (audioRef.current) audioRef.current.currentTime = progress;
  };

  const formatTime = (seconds: number) => {
    if (!seconds || isNaN(seconds)) return "-:--";
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    setTouchStart({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY });
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (!touchStart) return;
    const touchEndX = e.changedTouches[0].clientX;
    const touchEndY = e.changedTouches[0].clientY;
    const diffX = touchStart.x - touchEndX;
    const diffY = touchStart.y - touchEndY;

    if (Math.abs(diffX) > 50 && Math.abs(diffX) > Math.abs(diffY)) {
      if (diffX > 0) nextSong();
      else prevSong();
    }

    // Swipe Down to close (only if menu is not open)
    if (diffY < -80 && Math.abs(diffY) > Math.abs(diffX) && !isMoreMenuOpen) {
        setFullScreen(false);
    }
    setTouchStart(null);
  };

  // --- ACTIONS ---
  const handleViewArtist = () => {
      if (!currentSong) return;
      setFullScreen(false);
      setIsMoreMenuOpen(false);
      navigate(`/artist/${currentSong.artists.primary[0].id}`, { 
          state: { artist: currentSong.artists.primary[0] } 
      });
  };

  const handleViewAlbum = () => {
      if (!currentSong) return;
      setFullScreen(false);
      setIsMoreMenuOpen(false);
      navigate(`/album/${currentSong.album.id}`);
  };

  const handleShare = () => {
      const url = window.location.href;
      navigator.clipboard.writeText(url);
      alert("Link copied to clipboard!");
      setIsMoreMenuOpen(false);
  };

  const handleAddToPlaylist = (playlistId: string) => {
      if (!currentSong) return;
      addSongToPlaylist(playlistId, currentSong);
      setShowPlaylistSelector(false);
      setIsMoreMenuOpen(false);
  };

  if (!currentSong) return null;

  const imageUrl = getImageUrl(currentSong.image);
  const primaryArtistName = currentSong.artists?.primary?.[0]?.name || currentSong.artists?.all?.[0]?.name || "Unknown Artist";

  const transitionConfig = {
    type: "tween",
    ease: "circOut",
    duration: 0.3
  };

  return (
    <>
        <audio 
            ref={audioRef}
            preload="auto"
            onTimeUpdate={handleTimeUpdate}
            onEnded={nextSong}
            onWaiting={() => setIsBuffering(true)}
            onPlaying={() => setIsBuffering(false)}
            onCanPlay={() => setIsBuffering(false)}
            onPause={() => {
                if (isPlaying && !isBuffering && audioRef.current?.paused && audioRef.current?.readyState > 2) setIsPlaying(false);
            }}
            onPlay={() => !isPlaying && setIsPlaying(true)}
            onError={() => { setIsBuffering(false); setIsPlaying(false); }}
        />

        <AnimatePresence mode="wait"> 
        {isFullScreen ? (
            /* --- FULL PLAYER --- */
            <motion.div 
                key="full-player"
                initial={{ y: "100%" }}
                animate={{ y: 0 }}
                exit={{ y: "100%" }}
                transition={{ 
                   type: "tween", 
                   ease: "circOut",
                   duration: 0.3
                }}
                className="fixed inset-0 z-[200] flex flex-col bg-[#121212] overflow-hidden font-sans touch-none"
                onClick={(e) => e.stopPropagation()}
                onTouchStart={handleTouchStart}
                onTouchEnd={handleTouchEnd}
            >
                {/* Dynamic Background */}
                <div 
                    className="absolute inset-0 z-0 pointer-events-none transition-colors duration-700 ease-in-out"
                    style={{ background: `linear-gradient(to bottom, ${dominantColor}, #121212)` }}
                />

                <div className="relative z-10 flex flex-col h-full text-white px-6 pb-8 pt-safe-top md:px-12 md:pb-12">

                    {/* Header */}
                    <div className="flex items-center justify-between shrink-0 h-16 mt-2">
                        <button onClick={() => setFullScreen(false)} className="p-2 -ml-2 hover:bg-white/10 rounded-full active:scale-95 transition-transform">
                            <ChevronDown size={28} className="text-white" />
                        </button>
                        <div className="flex flex-col items-center opacity-80">
                            <span className="text-[10px] font-bold tracking-[0.2em] uppercase text-white/60">
                                {isOfflineMode ? "Offline Mode" : "Now Playing"}
                            </span>
                        </div>
                        <button 
                            onClick={() => { setShowPlaylistSelector(false); setIsMoreMenuOpen(true); }}
                            className="p-2 -mr-2 hover:bg-white/10 rounded-full active:scale-95 transition-transform"
                        >
                            <MoreHorizontal size={24} className="text-white" />
                        </button>
                    </div>

                    {/* Album Art */}
                    <div className="flex-1 flex items-center justify-center py-4 min-h-0">
                         <div className="relative w-full max-w-[340px] aspect-square">
                            <motion.img 
                                layoutId="player-image"
                                src={imageUrl} 
                                alt={currentSong.name} 
                                className="w-full h-full object-cover rounded-xl shadow-[0_8px_40px_rgba(0,0,0,0.5)]"
                                transition={transitionConfig}
                            />
                         </div>
                    </div>

                    {/* Track Info */}
                    <div className="flex flex-col gap-6 shrink-0 w-full max-w-lg mx-auto mb-6 md:mb-10">
                        <div className="flex items-center justify-between">
                            <div className="flex flex-col overflow-hidden mr-6 flex-1">
                                <motion.h1 
                                    initial={{ opacity: 0, x: -20 }}
