                            {/* Buttons */}
                            <div className="flex items-center justify-between -mx-2 mt-4">
                                <button className={`p-2 ${isShuffling ? 'text-[#1DB954]' : 'text-white/40'}`}><Shuffle size={20} /></button>

                                <div className="flex items-center gap-6 md:gap-10">
                                    <button onClick={prevSong} className="text-white hover:text-white/70 active:scale-90 transition-transform"><SkipBack size={32} fill="currentColor" /></button>
                                    <button 
                                        onClick={togglePlay}
