                                        disabled={isBuffering}
                                        className="bg-white text-black rounded-full w-16 h-16 flex items-center justify-center hover:scale-105 active:scale-90 transition-all shadow-md"
                                    >
                                        {isBuffering ? <Loader2 size={32} className="animate-spin" /> : isPlaying ? <Pause size={32} fill="currentColor" /> : <Play size={32} fill="currentColor" className="ml-1" />}
                                    </button>
                                    <button onClick={nextSong} className="text-white hover:text-white/70 active:scale-90 transition-transform"><SkipForward size={32} fill="currentColor" /></button>
                                </div>

                                <button className="p-2 text-white/40"><Repeat size={20} /></button>
                            </div>
                        </motion.div>
                    </div>

                    {/* Bottom Actions */}
                    <motion.div 
                        initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 0.3 }}
                        className="flex items-center justify-between px-2"
                    >
